INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-12-15', E'이스라엘의 구원 (이사야 48장)', E'이사야 48장', E'이사야 48장은 하나님께서 이스라엘 백성의 모순된 신앙을 적나라하게 드러내시는 말씀입니다. "여호와의 이름으로 맹세하며 이스라엘의 하나님을 기념하면서도 진실이 없고 공의가 없도다"(48:1). 입술로는 하나님을 부르지만 삶에는 진실함이 없는 형식적 신앙의 민낯이 그대로 드러납니다. 거룩한 성 출신이라 자부하면서도 실제로는 쇠의 힘줄같이 굳은 목과 놋같이 완고한 이마를 가진 백성의 모습은 오늘날 우리의 자화상일지도 모릅니다.\n\n하나님은 이런 백성의 완고함을 이미 아셨기에 예로부터 장래 일을 미리 알려주셨습니다. 이는 그들이 "내 신이 행한 바요 내가 새긴 신상과 부어 만든 신상이 명령한 바라"(48:5) 말하지 못하게 하려는 것이었습니다. 하나님의 예언이 성취될 때마다 그것이 우상의 능력이 아닌 여호와 하나님의 주권적 역사임을 분명히 하신 것입니다. 더 나아가 하나님은 "네가 과연 듣지도 못하였고 알지도 못하였으며 네 귀가 옛적부터 열리지 못하였나니"(48:8)라고 말씀하시며, 백성이 모태에서부터 배역한 자임을 지적하십니다.\n\n그런데 놀라운 것은 이런 백성을 향한 하나님의 반응입니다. "내 이름을 위하여 내가 노하기를 더디 할 것이며 내 영광을 위하여 내가 참고 너를 멸절하지 아니하리라"(48:9). 마땅히 심판받아야 할 백성이지만 하나님은 당신의 이름과 영광을 위해 참으시고, "고난의 풀무 불에서 택하였노라"(48:10)고 선언하십니다. 고난은 버리시기 위함이 아니라 정련하여 택하시기 위한 사랑의 도구였습니다.\n\n이어서 하나님은 자신이 처음이요 마지막이며, 땅의 기초를 정하고 하늘을 펴신 창조주임을 상기시키십니다. 그리고 "네가 나의 명령에 주의하였더라면 네 평강이 강과 같았겠고 네 공의가 바다 물결 같았을 것"(48:18)이라며 안타까워하십니다. 순종했더라면 누릴 수 있었던 복을 놓친 것에 대한 하나님의 애통함이 느껴집니다. 그럼에도 하나님은 바벨론에서 나와 갈대아인을 피하라고 명하시며, 출애굽 때처럼 바위에서 물을 내어 목마르지 않게 하실 것을 약속하십니다.\n\n오늘도 우리는 입술로는 주님을 부르면서도 삶에는 진실함이 결여된 모습으로 살아갈 때가 많습니다. 그러나 하나님은 우리의 연약함을 아시고도 당신의 이름을 위해 참으시며, 고난의 풀무를 통해서라도 우리를 정련하여 택하기를 원하십니다.', E'오늘의 핵심\n하나님은 형식적 신앙과 완고함으로 가득한 백성을 멸하지 않으시고, 오히려 고난의 풀무에서 정련하여 택하시며 새로운 구원의 길을 여십니다.\n\n묵상 질문\n1. 나의 신앙생활 중 입술로만 고백하고 삶으로는 실천하지 못하는 부분은 무엇인가요?\n2. 지금 겪는 고난이 하나님의 정련 과정일 수 있다면, 어떤 마음으로 받아들이시겠습니까?\n3. "네가 나의 명령에 주의하였더라면"이라는 하나님의 안타까움에 어떻게 응답하시겠습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-12-16', E'이스라엘의 구원 (이사야 49장)', E'이사야 49장', E'이사야 49장은 하나님께서 택하신 종이 자신의 사명을 고백하며 시작됩니다. "여호와께서 태에서부터 나를 부르셨고 내 어머니의 복중에서부터 내 이름을 기억하셨으며"(49:1). 이 종은 단순히 이스라엘을 회복시키는 것을 넘어 "이방의 빛"이 되어 구원을 땅 끝까지 이르게 할 사명을 받았습니다. 하나님은 그를 날카로운 칼과 갈고 닦은 화살로 준비시키셨지만, 정작 그는 "내가 헛되이 수고하였으며 무익하게 공연히 내 힘을 다하였다"고 탄식합니다. 사역의 열매가 보이지 않을 때 느끼는 좌절감이 그대로 드러납니다.\n\n그러나 하나님의 계획은 인간의 좌절을 뛰어넘습니다. 야곱의 지파를 일으키는 것은 "매우 쉬운 일"이라 하시며, 더 큰 사명으로 부르십니다. 멸시받고 미움받는 종이 결국 왕들이 일어서고 고관들이 경배하는 존재가 될 것이라는 약속은 십자가에서 영광으로 나아가신 그리스도의 길을 보여줍니다.\n\n백성들의 절망은 더욱 깊습니다. "여호와께서 나를 버리시며 주께서 나를 잊으셨다"는 시온의 탄식에 하나님은 놀라운 비유로 응답하십니다. 어머니가 젖 먹는 자식을 잊을 수 없듯이, 아니 그 이상으로 하나님은 우리를 잊지 않으신다고 약속하십니다. "내가 너를 내 손바닥에 새겼고"라는 표현은 영원히 지워지지 않는 하나님의 사랑을 보여줍니다.\n\n포로 생활의 고통 속에서 자녀를 잃고 홀로 남았다고 생각했던 이스라엘에게, 하나님은 예상치 못한 회복을 약속하십니다. 황폐한 땅이 주민으로 가득 차고, 잃었던 자녀들보다 더 많은 자녀들이 돌아와 "이곳이 내게 좁으니 넓혀달라"고 할 정도가 될 것입니다. 용사의 포로도 빼앗고 두려운 자의 빼앗은 것도 건져내실 전능하신 하나님의 구원이 선포됩니다.\n\n오늘 우리도 사역의 열매가 보이지 않아 좌절하거나, 하나님이 나를 잊으신 것은 아닐까 의심할 때가 있습니다. 그러나 하나님은 우리의 이름을 손바닥에 새기신 분이십니다. 비록 지금은 황폐한 것처럼 보여도, 하나님의 때에 놀라운 회복과 번영을 주실 것을 믿고 기다리는 것이 믿음입니다.', E'오늘의 핵심\n하나님은 절망 속에 있는 백성에게 손바닥에 새긴 사랑으로 응답하시며, 예상치 못한 방법으로 완전한 회복을 이루실 것을 약속하십니다.\n\n묵상 질문\n1. 내가 헛되이 수고한다고 느낄 때, 하나님의 더 큰 계획을 신뢰하고 있나요?\n2. 하나님이 나를 잊으셨다고 느껴질 때, 그분의 변함없는 사랑을 어떻게 기억할 수 있을까요?\n3. 하나님의 회복을 기다리며 오늘 내가 붙들어야 할 약속의 말씀은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-12-17', E'이스라엘의 구원 (이사야 50장)', E'이사야 50장', E'이사야 50장은 하나님의 신실하심과 인간의 불신실함이 극명하게 대비되는 본문입니다. 하나님은 이스라엘을 내보내신 것이 이혼이 아니라 그들의 죄로 인한 일시적 분리임을 분명히 하십니다. "내가 너희의 어미를 내보낸 이혼 증서가 어디 있느냐"(사 50:1)는 수사적 질문은 하나님께서 여전히 그들의 남편이시며, 언약의 관계가 끊어지지 않았음을 보여줍니다. \n\n그런데 하나님이 오셨을 때 아무도 응답하지 않았다는 것이 이스라엘의 비극입니다. 바다를 마르게 하시고 강을 사막으로 만드실 수 있는 전능하신 분께서 구원의 손길을 내미셨건만, 백성들은 침묵으로 일관했습니다. 이것은 오늘날 우리의 모습이기도 합니다. 하나님의 음성이 들려와도, 은혜의 초대가 있어도 우리는 너무나 자주 다른 것들에 마음을 빼앗긴 채 응답하지 못합니다.\n\n본문의 중반부터는 놀라운 전환이 일어납니다. 여호와의 종이 등장하여 자신의 소명과 고난을 고백합니다. 이 종은 매일 아침 하나님께로부터 가르침을 받아 곤고한 자를 위로할 말을 배웁니다. 더욱 놀라운 것은 이 종이 자발적으로 고난을 받아들인다는 사실입니다. 등을 맞고, 수염을 뽑히고, 침 뱉음을 당하면서도 얼굴을 가리지 않는 이 모습은 훗날 예수 그리스도께서 걸어가실 십자가의 길을 예표합니다.\n\n"주 여호와께서 나를 도우시므로 내가 부끄러워하지 아니하고"라는 종의 고백은 고난 중에도 흔들리지 않는 믿음의 본을 보여줍니다. 세상이 조롱하고 정죄해도, 하나님께서 의롭다 하시는 이가 가까이 계시기에 담대할 수 있습니다. \n\n마지막으로 본문은 두 종류의 사람을 대조합니다. 흑암 중에 있으면서도 여호와를 의뢰하는 자와, 스스로 불을 피워 자기 빛으로 걸어가려는 자입니다. 자기 힘으로 어둠을 밝히려는 이들은 결국 자신이 피운 불에 타서 고통 가운데 누울 것입니다. 그러나 빛이 없는 흑암 속에서도 하나님을 의지하는 자는 참된 구원을 경험하게 됩니다.', E'오늘의 핵심\n하나님은 백성의 불신실함에도 불구하고 여전히 구원의 손길을 내미시며, 고난받는 종을 통해 참된 구원의 길을 보여주십니다.\n\n묵상 질문\n1. 하나님께서 부르실 때 나는 어떻게 응답하고 있습니까?\n2. 고난 중에도 하나님을 의지할 수 있는 믿음이 내게 있습니까?  \n3. 내 스스로 만든 빛이 아닌 하나님의 빛을 구하며 살고 있습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-12-18', E'고난 받는 종 (이사야 53장)', E'이사야 53장', E'이사야 선지자는 장차 오실 메시아의 모습을 놀랍도록 선명하게 그려내고 있습니다. 그런데 그 모습은 우리의 기대와는 전혀 다른 것이었습니다. "연한 순 같고 마른 땅에서 나온 뿌리"(사 53:2)라는 표현은 메시아가 화려하거나 위엄 있는 모습이 아니라 보잘것없고 연약한 모습으로 오실 것을 보여줍니다. 실제로 예수님은 작은 시골 마을 나사렛에서 목수의 아들로 태어나셨고, 세상의 권세자들이 아닌 가난한 자들과 병든 자들의 친구가 되셨습니다.\n\n더욱 충격적인 것은 이 종이 받을 고난의 내용입니다. 이사야는 메시아가 멸시와 천대를 받고, 슬픔과 질고를 짊어지며, 찔림과 상함을 당할 것이라고 예언합니다. 그런데 이 모든 고난이 그분 자신의 죄 때문이 아니라 "우리의 허물" 때문이며 "우리의 죄악" 때문이라는 사실이 계속해서 강조됩니다. 특별히 6절은 인간의 본질적인 문제를 적나라하게 드러냅니다. 우리는 모두 길 잃은 양처럼 각자 제 갈 길로 흩어졌지만, 하나님께서는 그 모든 죄의 무게를 한 분에게 지우셨다는 것입니다.\n\n도수장으로 끌려가는 어린 양의 침묵은 십자가를 향해 가시는 예수님의 순종을 미리 보여줍니다. 빌라도 앞에서, 헤롯 앞에서, 조롱하는 군중들 앞에서 예수님은 자신을 변호하지 않으셨습니다. 이는 연약함이 아니라 아버지의 뜻에 대한 완전한 순종이었습니다. 10절은 이 모든 일이 우연히 일어난 것이 아니라 여호와께서 계획하신 일임을 분명히 합니다. 하나님은 자기 아들을 속건제물로 드림으로써 많은 사람을 의롭게 하시는 놀라운 구원의 계획을 성취하셨습니다.\n\n이사야가 그린 고난받는 종의 초상은 700년 후 갈보리 언덕에서 완벽하게 성취되었습니다. 우리가 평화를 누리는 것은 그분이 징계를 받으셨기 때문이며, 우리가 나음을 받은 것은 그분이 채찍에 맞으셨기 때문입니다. 이것이 복음의 핵심이며, 하나님의 사랑의 극치입니다.', E'오늘의 핵심\n고난받는 종 메시아는 우리의 죄와 허물을 대신 짊어지고 십자가에서 죽으심으로써 우리에게 평화와 치유를 가져다주셨습니다. 이것이 하나님의 구원 계획의 중심입니다.\n\n묵상 질문\n1. 내가 기대하는 메시아의 모습과 이사야가 그린 고난받는 종의 모습은 어떻게 다른가요?\n2. "우리는 다 양 같아서 그릇 행하여 각기 제 길로 갔거늘"이라는 말씀이 내 삶에서는 어떻게 나타나고 있나요?\n3. 예수님이 나를 위해 받으신 고난을 묵상할 때, 오늘 내가 드려야 할 감사와 헌신은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-12-20', E'고난 받는 종 (이사야 54장)', E'이사야 54장', E'포로기를 겪는 이스라엘에게 하나님께서는 놀라운 회복의 약속을 선포하십니다. 이사야는 출산하지 못한 여인의 비유를 통해 현재의 고통과 미래의 영광을 대비시켜 보여줍니다. 바벨론 포로로 끌려간 이스라엘은 마치 남편을 잃고 자녀도 없는 여인과 같았습니다. 그러나 하나님께서는 이런 절망적인 상황에서 오히려 "노래하라"고 명령하십니다. 황폐해진 예루살렘이 다시 많은 백성으로 채워질 것이며, 그 자손들이 열방을 얻을 것이라는 약속이 주어집니다.\n\n특별히 하나님께서는 자신을 이스라엘의 "남편"이자 "구속자"로 계시하십니다. "이는 너를 지으신 이가 네 남편이시라 그의 이름은 만군의 여호와이시며 네 구속자는 이스라엘의 거룩한 이시라"(사 54:5)는 선언은 하나님과 이스라엘의 관계가 단순한 주종 관계가 아닌 사랑의 언약 관계임을 보여줍니다. 포로기라는 징계는 잠시뿐이며, 하나님의 영원한 자비와 긍휼이 그들을 다시 모으실 것입니다.\n\n이 회복의 약속은 노아 언약과 연결되어 더욱 확실해집니다. 하나님께서 다시는 홍수로 땅을 멸하지 않겠다고 맹세하신 것처럼, 이스라엘을 향한 진노도 영원하지 않을 것입니다. 오히려 하나님께서는 보석으로 예루살렘을 재건하시고, 그들의 자녀들에게 평안을 주시며, 모든 대적으로부터 보호하실 것을 약속하십니다. 이는 단순한 물리적 회복을 넘어 영적이고 영원한 구원을 가리키며, 궁극적으로는 메시아를 통한 새 언약의 성취를 바라보게 합니다. 하나님의 신실하심은 우리의 실패보다 크며, 그분의 사랑은 우리의 배반보다 깊습니다.', E'오늘의 핵심\n하나님께서는 포로기의 절망 속에서도 이스라엘을 버리지 않으시고, 영원한 사랑의 언약으로 그들을 회복시키실 것을 약속하십니다.\n\n묵상 질문\n1. 절망적인 상황에서도 하나님께서 "노래하라"고 하신 이유는 무엇일까요?\n2. 하나님을 ''남편''으로, ''구속자''로 부르는 것이 내게 주는 위로는 무엇인가요?\n3. 내 삶의 어떤 영역에서 하나님의 회복의 약속을 붙잡고 믿음으로 나아가야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-12-21', E'고난 받는 종 (이사야 55장)', E'이사야 55장', E'이사야 55장은 하나님께서 베푸시는 은혜의 잔치에 대한 초대장입니다. "오호라 너희 모든 목마른 자들아 물로 나아오라 돈 없는 자도 오라"(사 55:1)는 외침으로 시작되는 이 장은 값없이 주시는 구원의 은혜를 생생하게 보여줍니다. 포로 생활의 고통 속에서 지친 이스라엘 백성들에게 하나님은 생명수와 같은 위로의 말씀을 전하십니다.\n\n이 초대는 단순히 물질적인 풍요를 약속하는 것이 아닙니다. 하나님께서는 백성들이 헛된 것에 힘을 쏟고 있음을 지적하시며, 참된 만족은 오직 하나님과의 관계 회복에서 온다는 것을 가르쳐 주십니다. "너희가 어찌하여 양식이 아닌 것을 위하여 은을 달아 주며 배부르게 하지 못할 것을 위하여 수고하느냐"는 물음은 오늘날 우리에게도 동일하게 던져지는 질문입니다.\n\n특별히 주목할 점은 하나님께서 다윗과 맺으신 영원한 언약을 언급하시는 부분입니다. 이 언약은 다윗의 후손을 통해 오실 메시아, 곧 예수 그리스도를 가리키는 것으로, 만민의 인도자요 명령자가 되실 그분을 통해 이방인까지도 구원의 대상이 됨을 보여줍니다. 이는 이사야 53장에서 예언된 고난받는 종의 사역이 가져올 놀라운 결과입니다.\n\n하나님의 생각과 길이 우리와 다르다는 선언은 인간의 제한된 이해력으로는 하나님의 구원 계획을 온전히 파악할 수 없음을 일깨워 줍니다. 그러나 하늘에서 내리는 비와 눈이 반드시 땅을 적시고 열매를 맺게 하듯이, 하나님의 말씀도 헛되이 돌아오지 않고 반드시 그 목적을 이룬다는 확신을 주십니다. 이 약속은 포로에서 돌아올 백성들뿐 아니라, 말씀을 붙드는 모든 시대의 신앙인들에게 주시는 변함없는 소망입니다.', E'오늘의 핵심\n하나님께서는 목마른 영혼들을 값없이 베푸시는 은혜의 잔치로 초대하시며, 그분의 말씀은 반드시 약속된 구원을 성취할 것입니다.\n\n묵상 질문\n1. 내가 양식이 아닌 것을 위해 수고하고 있는 영역은 무엇인가요?\n2. 하나님의 생각과 길이 나와 다를 때, 어떻게 신뢰하며 순종할 수 있을까요?\n3. 오늘 하나님께서 나를 초대하시는 은혜의 자리는 어디인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-12-22', E'참된 회개 (이사야 56장)', E'이사야 56장', E'이사야 56장은 포로 귀환 이후 새로운 시대를 맞이할 이스라엘에게 주어진 놀라운 구원의 선포로 시작됩니다. 하나님께서는 "너희는 정의를 지키며 의를 행하라 이는 나의 구원이 가까이 왔고 나의 공의가 나타날 것임이라"(사 56:1)고 말씀하십니다. 이 구원의 약속은 단순히 이스라엘만을 위한 것이 아니라 모든 민족을 향한 것이었습니다. \n\n특별히 주목할 것은 그동안 언약 공동체에서 배제되었던 이방인과 고자들에 대한 하나님의 따뜻한 초청입니다. 당시 율법에 따르면 고자는 여호와의 회중에 들어올 수 없었고, 이방인들은 선민 이스라엘과 구별되는 존재였습니다. 그러나 하나님께서는 이들이 안식일을 지키고 언약을 굳게 잡으면 성전에서 예배할 수 있을 뿐 아니라 "아들이나 딸보다 나은 기념물과 이름"을 주시겠다고 약속하십니다. 이는 혈통이나 육체적 조건이 아닌 믿음과 순종으로 하나님의 백성이 되는 새로운 시대가 열렸음을 보여줍니다.\n\n하나님의 집이 "만민이 기도하는 집"이 될 것이라는 선언은 구약의 배타적 선민사상을 넘어서는 혁명적인 메시지였습니다. 이는 훗날 예수님께서 성전을 정화하시며 인용하신 말씀이기도 합니다. 하나님께서는 이스라엘뿐 아니라 모든 민족을 구원하시기 원하셨고, 이스라엘은 그 통로가 되어야 했습니다.\n\n그러나 안타깝게도 이스라엘의 지도자들은 이러한 하나님의 마음을 이해하지 못했습니다. 선지자는 그들을 "맹인 파수꾼"과 "벙어리 개"에 비유하며 신랄하게 비판합니다. 백성을 돌보고 경고해야 할 지도자들이 오히려 자기 이익만을 추구하며 영적으로 잠들어 있었던 것입니다. 그들은 포도주에 취해 있으면서도 내일도 오늘과 같을 것이라는 안일한 생각에 빠져 있었습니다.\n\n이 말씀은 오늘날 교회와 그리스도인들에게도 중요한 도전을 줍니다. 하나님의 구원은 모든 사람을 향해 열려 있으며, 우리는 그 구원의 통로가 되어야 합니다. 동시에 영적 지도자들은 깨어 있어 양 떼를 올바로 인도해야 할 책임이 있습니다.', E'오늘의 핵심\n하나님께서는 혈통이나 육체적 조건이 아닌 믿음과 순종으로 모든 사람을 받아주시며, 그의 집을 만민이 기도하는 집으로 만드시고자 하십니다.\n\n묵상 질문\n1. 하나님께서 이방인과 고자까지 받아주시는 것을 보며 어떤 은혜를 느끼십니까?\n2. 나는 혹시 어떤 사람들을 하나님의 구원에서 제외시키고 있지는 않나요?\n3. 영적 파수꾼으로서 깨어 있기 위해 오늘 무엇을 결단하시겠습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-12-23', E'참된 회개 (이사야 57장)', E'이사야 57장', E'이사야 선지자는 당시 유다 사회의 영적 타락상을 적나라하게 드러내면서, 하나님의 심판과 회복의 메시지를 전합니다. 의인들이 죽어가는데도 아무도 관심을 갖지 않고, 진실한 사람들이 사라져도 깨닫는 이가 없는 시대였습니다. 하나님은 이러한 백성들의 무관심 속에서도 의인들을 평안으로 인도하시며, 그들이 바른 길을 걸었기에 침상에서 편히 쉬게 하신다고 말씀하십니다.\n\n하나님께서는 우상숭배에 빠진 백성들을 "무당의 자식, 간음자와 음녀의 자식들"이라 부르시며 그들의 죄악을 폭로하십니다. 그들은 상수리나무 아래서 음욕을 피우고, 골짜기에서 자녀를 제물로 바치는 가증한 일을 행했습니다. 높은 산 위에 제단을 쌓고, 몰렉에게 향품을 바치며, 심지어 스올에까지 사신을 보내는 그들의 모습은 하나님을 완전히 떠난 백성의 처참한 영적 상태를 보여줍니다.\n\n그러나 놀라운 것은 이렇게 타락한 백성들에게도 하나님의 회복의 약속이 주어진다는 사실입니다. "내가 높고 거룩한 곳에 있으며 또한 통회하고 마음이 겸손한 자와 함께 있나니"(사 57:15)라는 말씀은 하나님의 초월적 거룩함과 동시에 겸손한 자를 향한 그분의 자비로운 임재를 보여줍니다. 하나님은 영원히 다투지 않으시고 끊임없이 노하지 않으실 것이라고 약속하십니다.\n\n하나님께서는 탐심의 죄악으로 패역한 길을 걷는 백성들을 치셨지만, 여전히 그들을 고치시고 인도하시며 위로를 주시겠다고 선포하십니다. 먼 데 있는 자에게든지 가까운 데 있는 자에게든지 평강을 주시는 하나님의 은혜는 참으로 놀랍습니다. 다만 끝까지 회개하지 않는 악인들에게는 평강이 없을 것이라는 엄중한 경고도 함께 주어집니다. 이는 하나님의 은혜가 값싼 것이 아니라, 진정한 회개와 겸손을 요구하는 거룩한 초청임을 보여줍니다.', E'오늘의 핵심\n하나님은 우상숭배로 타락한 백성을 심판하시지만, 통회하고 겸손한 마음으로 돌아오는 자들에게는 고침과 평강의 은혜를 약속하십니다.\n\n묵상 질문\n1. 내 삶에서 하나님보다 더 의지하고 있는 우상은 무엇인가요?\n2. 통회하고 겸손한 마음으로 하나님께 나아갈 때 경험한 회복의 은혜가 있나요?\n3. 악인에게는 평강이 없다는 말씀이 오늘 나에게 주는 경고는 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-12-24', E'참된 회개 (이사야 58장)', E'이사야 58장', E'하나님께서는 이사야를 통해 백성들의 잘못된 종교생활을 날카롭게 지적하십니다. 이스라엘 백성들은 겉으로는 경건한 모습으로 금식하고 예배하며 하나님을 찾았지만, 그들의 삶은 여전히 불의와 위선으로 가득했습니다. 금식하는 날에도 자신들의 이익을 추구하고, 종들을 혹사시키며, 서로 다투고 악한 주먹으로 치는 모습은 그들의 신앙이 얼마나 형식적이었는지를 보여줍니다.\n\n하나님께서 진정으로 기뻐하시는 금식은 굵은 베옷을 입고 재를 뿌리는 외적인 행위가 아니라, 억압받는 자들을 자유롭게 하고 굶주린 자들과 양식을 나누는 것이었습니다. "내가 기뻐하는 금식은 흉악의 결박을 풀어 주며 멍에의 줄을 끌러 주며 압제 당하는 자를 자유하게 하며 모든 멍에를 꺾는 것이 아니겠느냐"(사 58:6)라는 말씀은 하나님의 관심이 종교적 의식이 아닌 정의와 사랑의 실천에 있음을 분명히 보여줍니다.\n\n이스라엘이 형제를 돌보고 약자를 섬길 때, 하나님께서는 놀라운 약속을 주십니다. 그들의 빛이 새벽같이 비치고, 치유가 급속히 일어나며, 메마른 곳에서도 영혼이 만족함을 얻게 될 것입니다. 더 나아가 그들은 황폐한 곳을 재건하는 자, 무너진 것을 보수하는 자로 불릴 것입니다. 안식일 준수에 대한 가르침 역시 단순한 율법 준수가 아닌, 하나님과의 관계 회복과 이웃 사랑의 실천으로 이어집니다.\n\n이 말씀은 오늘날 우리에게도 동일하게 적용됩니다. 주일예배와 새벽기도, 금식기도에 열심을 내면서도 일상에서 이웃을 외면하고 있다면, 우리 역시 이스라엘과 다르지 않습니다. 하나님께서는 우리의 예배가 삶으로 이어지기를 원하십니다. 교회 안에서의 경건이 세상 속에서의 정의와 사랑으로 나타날 때, 비로소 우리는 세상의 빛이 되고 하나님께서 약속하신 회복과 치유를 경험하게 될 것입니다.', E'오늘의 핵심\n하나님께서 기뻐하시는 참된 금식과 예배는 종교적 형식이 아니라 억압받는 자를 자유롭게 하고 굶주린 자와 나누는 정의와 사랑의 실천입니다.\n\n묵상 질문\n1. 나의 신앙생활이 교회 안에서만 머물고 있지는 않은가요? 일상에서 이웃을 향한 사랑으로 이어지고 있나요?\n2. 하나님께서 기뻐하시는 금식의 의미를 깨달았다면, 오늘 내가 풀어줄 수 있는 누군가의 멍에는 무엇일까요?\n3. 형식적인 종교생활에서 벗어나 진정한 예배자로 살기 위해 내가 변화해야 할 부분은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-12-25', E'참된 회개 (이사야 59장)', E'이사야 59장', E'이사야 59장은 이스라엘 백성이 하나님께 드린 원망에 대한 명확한 답변을 담고 있습니다. 백성들은 자신들이 겪는 고난과 열방의 침략 앞에서 하나님께서 침묵하신다고 생각했습니다. 그러나 하나님께서는 문제의 원인이 그분께 있지 않고 백성들의 죄에 있음을 분명히 밝히십니다. "여호와의 손이 짧아 구원하지 못하심도 아니요 귀가 둔하여 듣지 못하심도 아니라"(사 59:1)는 선언은 하나님의 능력과 사랑이 여전히 변함없음을 보여줍니다.\n\n선지자는 백성들의 죄악상을 구체적으로 묘사합니다. 손은 피로, 입술은 거짓으로, 혀는 악독으로 더러워졌으며, 그들의 행위는 독사의 알을 품는 것과 같아서 결국 독이 되어 자신들을 해치게 됩니다. 거미줄을 짜듯 헛된 일에 매달리며, 그 결과물로는 자신들을 가릴 수도 없습니다. 이러한 묘사는 죄가 단순히 하나님과의 관계만 손상시키는 것이 아니라 인간 삶 전체를 파괴시킨다는 것을 생생하게 보여줍니다.\n\n그러나 이사야의 메시지는 절망으로 끝나지 않습니다. 백성들이 스스로를 구원할 수 없는 상황에서, 하나님께서 친히 구원자가 되어 오십니다. 사람이 없음을 보시고 중재자가 없음을 안타까워하신 하나님께서는 자기 팔로 직접 구원을 베푸시기로 결정하십니다. 공의를 갑옷으로, 구원을 투구로 삼으신 하나님의 모습은 그분이 단순히 심판자가 아니라 적극적인 구원자이심을 보여줍니다.\n\n마지막으로 하나님께서는 "구속자가 시온에 임하며 야곱의 자손 가운데에서 죄과를 떠나는 자에게 임하리라"고 약속하십니다. 이는 회개하고 돌아오는 자들에게 여전히 구원의 문이 열려 있음을 의미합니다. 나아가 하나님의 영과 말씀이 그들과 그 후손들에게 영원히 함께할 것이라는 언약은, 일시적 구원이 아닌 영원한 관계 회복을 약속하는 것입니다.', E'오늘의 핵심\n우리의 죄가 하나님과의 관계를 가로막는 장벽이 되지만, 회개하고 돌아오는 자들을 위해 하나님께서는 친히 구원자가 되어 주십니다.\n\n묵상 질문\n1. 내 삶의 어려움을 하나님께 원망하기보다 먼저 돌아보아야 할 나의 죄는 무엇입니까?\n2. 하나님께서 공의의 갑옷을 입고 구원자로 오신다는 약속이 오늘 나에게 어떤 위로가 됩니까?\n3. 하나님의 영과 말씀이 나와 내 후손에게 영원히 함께한다는 약속을 믿고 있습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-12-27', E'구원의 아름다운 소식 (이사야 60장)', E'이사야 60장', E'이사야는 포로기를 겪고 있는 이스라엘 백성에게 놀라운 회복의 비전을 전해줍니다. "일어나라 빛을 발하라"는 하나님의 부르심은 어둠 속에서 절망하고 있던 백성들에게 새로운 희망의 메시지였습니다. 비록 지금은 바벨론 포로라는 캄캄한 현실 속에 있지만, 여호와의 영광이 다시 시온 위에 임할 것이라는 약속이 주어집니다.\n\n이사야가 전하는 회복의 모습은 단순히 이전 상태로 돌아가는 것이 아닙니다. 하나님께서는 이스라엘을 통해 온 세상을 비추실 계획을 가지고 계셨습니다. 이방 나라들이 이스라엘의 빛으로 나아오고, 왕들이 그 광명을 따라올 것이라는 예언은 하나님의 구원 계획이 한 민족을 넘어 온 인류를 향한 것임을 보여줍니다. 흩어졌던 자녀들이 돌아오고, 열방의 재물이 시온으로 모여들며, 성전 예배가 회복되는 장면들은 하나님의 백성이 누릴 영광스러운 미래를 그려냅니다.\n\n특별히 주목할 것은 이 회복이 하나님의 은혜로 이루어진다는 점입니다. "내가 노하여 너를 쳤으나 이제는 나의 은혜로 너를 불쌍히 여겼은즉"(60:10)이라는 말씀은 심판이 하나님의 마지막 말씀이 아니었음을 분명히 합니다. 과거에 이스라엘을 괴롭히고 멸시했던 자들이 오히려 그들 앞에 엎드리고, 시온을 ''여호와의 성읍''이라 부르게 될 것입니다.\n\n이사야가 그리는 새 예루살렘의 모습은 더욱 놀랍습니다. 해와 달이 필요 없을 정도로 여호와 자신이 영원한 빛이 되시고, 다시는 슬픔과 애통이 없으며, 모든 백성이 의롭게 되어 영원히 땅을 차지하게 됩니다. 이는 단순한 정치적 회복을 넘어선 영적이고 우주적인 변화를 의미합니다. 작은 자가 천 명을 이루고 약한 자가 강국을 이룬다는 약속은 하나님의 능력으로 불가능이 가능케 됨을 선포합니다. 이 모든 일을 "때가 되면 나 여호와가 속히 이루리라"고 하신 하나님의 신실하심이 절망 중에 있는 백성들에게 확실한 소망이 되었을 것입니다.', E'오늘의 핵심\n하나님께서는 심판받아 어둠 속에 있던 이스라엘을 다시 일으키시고, 그들을 통해 온 열방을 비추는 빛이 되게 하시며, 영원한 빛이신 자신과 함께하는 새로운 미래를 약속하십니다.\n\n묵상 질문\n1. 어둠 같은 현실 속에서도 하나님의 영광의 빛을 기대하며 일어설 수 있나요?\n2. 하나님의 은혜로 회복된 내 삶이 다른 사람들에게 빛이 되고 있나요?\n3. 영원한 빛이신 하나님과 함께하는 삶을 오늘 어떻게 경험하고 계신가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-12-28', E'구원의 아름다운 소식 (이사야 61장)', E'이사야 61장', E'포로기의 어둠 속에서 이사야는 놀라운 소망의 메시지를 전합니다. "주 여호와의 영이 내게 내리셨으니"(사 61:1)로 시작하는 이 말씀은 메시아를 통한 완전한 회복의 청사진을 보여주고 있습니다. 가난한 자, 마음이 상한 자, 포로된 자, 갇힌 자 - 이들은 단지 바벨론 포로들만을 가리키는 것이 아니라, 죄와 절망에 갇힌 모든 인류를 대변합니다. \n\n이사야가 전하는 회복의 비전은 단순한 귀환 이상의 것입니다. 재를 대신하여 화관을, 슬픔을 대신하여 기쁨의 기름을, 근심을 대신하여 찬송의 옷을 주신다는 약속은 하나님께서 주시는 회복이 얼마나 완전하고 풍성한지를 보여줍니다. 특히 주목할 점은 회복된 백성들이 ''의의 나무''로 불리며 여호와의 영광을 나타내는 존재가 된다는 것입니다. 이는 단순한 구조(救助)가 아닌, 존재의 변화를 의미합니다.\n\n더 나아가 이 회복은 이스라엘을 넘어 열방으로 확장됩니다. 이방인들이 양 떼를 치고 농부가 되는 동안, 이스라엘은 ''여호와의 제사장''이 되어 열방을 섬기는 중보자의 역할을 감당하게 됩니다. 수치와 능욕이 배가 되는 보상과 영원한 기쁨으로 바뀌는 이 극적인 반전은, 하나님의 신실하신 언약에 기초합니다.\n\n이사야는 이 모든 약속을 듣고 억누를 수 없는 기쁨으로 찬양합니다. 구원의 옷과 공의의 겉옷을 입은 모습을 혼인 예복을 입은 신랑 신부에 비유하며, 하나님께서 이루실 구원의 확실함을 노래합니다. 마치 땅이 싹을 내고 동산이 뿌린 것을 움돋게 하듯, 하나님의 공의와 찬송이 모든 나라 앞에 나타날 것입니다. 이 모든 회복의 중심에는 메시아가 계시며, 그분을 통해 하나님의 은혜의 해가 선포될 것입니다.', E'오늘의 핵심\n하나님께서는 메시아를 통해 포로된 자를 자유케 하시고, 슬픔을 기쁨으로 바꾸시며, 그의 백성을 열방을 섬기는 제사장 나라로 회복시키실 것을 약속하십니다.\n\n묵상 질문\n1. 내 삶에서 ''재'' 대신 ''화관''으로 바뀌어야 할 영역은 무엇인가요?\n2. 하나님께서 나를 ''의의 나무''로 심으신 이유는 무엇일까요?\n3. 오늘 내가 제사장으로서 중보하고 섬겨야 할 사람은 누구인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-12-29', E'구원의 아름다운 소식 (이사야 62장)', E'이사야 62장', E'시온의 회복을 향한 하나님의 열정이 예언자의 입을 통해 선포되고 있습니다. 이사야는 예루살렘의 의가 빛처럼, 구원이 횃불처럼 나타날 때까지 잠잠하지 않겠다고 선언합니다. 이는 단순한 예언자의 다짐이 아니라 하나님의 변함없는 구원 의지를 대변하는 것입니다. 포로기의 어둠 속에서도 하나님께서는 당신의 백성을 향한 사랑을 포기하지 않으셨습니다.\n\n하나님께서 시온에게 주실 새로운 정체성은 놀랍도록 아름답습니다. ''버림받은 자''에서 ''헵시바''(나의 기쁨이 그녀에게 있다)로, ''황무지''에서 ''쁄라''(결혼한 여인)로 바뀔 것입니다. 이 새 이름들은 하나님과 백성 사이의 관계가 얼마나 친밀하게 회복될 것인지를 보여줍니다. 특히 신랑이 신부를 기뻐하는 것처럼 하나님께서 당신의 백성을 기뻐하신다는 표현은 구원의 기쁨이 얼마나 클지를 예고합니다.\n\n이사야는 예루살렘 성벽 위에 세워진 파수꾼들이 주야로 기도하며 하나님께서 약속을 성취하실 때까지 쉬지 말아야 한다고 권면합니다. 이는 하나님의 약속이 인간의 간절한 기도와 만날 때 성취된다는 것을 보여줍니다. 하나님께서는 당신의 오른손과 능력의 팔로 맹세하시며, 더 이상 이스라엘의 곡식과 포도주가 원수들에게 넘어가지 않을 것이라고 약속하십니다. 수고의 열매를 빼앗기는 고통은 끝날 것입니다.\n\n"성문으로 나아가라"는 외침은 구원의 날을 맞이할 준비를 촉구합니다. 백성이 돌아올 길을 닦고, 방해하는 돌들을 제거하며, 만민을 위한 기치를 드는 것은 하나님의 구원이 이스라엘만이 아닌 온 세상을 향한 것임을 보여줍니다. 결국 하나님의 백성은 ''거룩한 백성'', ''여호와께서 구속하신 자'', ''찾은 바 된 자'', ''버림받지 아니한 성읍''이라는 영광스러운 이름으로 불리게 될 것입니다. 이 모든 약속은 오늘날 그리스도 안에서 우리에게도 주어진 소망입니다.', E'오늘의 핵심\n하나님께서는 시온을 향한 불타는 사랑으로 그들의 수치를 영광으로, 버림받음을 기쁨으로 바꾸시며, 신랑이 신부를 기뻐함같이 당신의 백성을 기뻐하실 것을 약속하십니다.\n\n묵상 질문\n1. 하나님께서 나에게 주신 ''새 이름''은 무엇이며, 그것이 내 정체성을 어떻게 바꾸었나요?\n2. 파수꾼처럼 포기하지 않고 기도해야 할 약속의 말씀은 무엇인가요?\n3. 하나님의 구원의 길을 예비하기 위해 내가 제거해야 할 ''돌''은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-12-30', E'구원의 아름다운 소식 (이사야 63장)', E'이사야 63장', E'에돔에서 오는 한 전사의 모습이 장엄하게 펼쳐집니다. 붉은 옷을 입고 보스라에서 나타나신 이 분은 바로 심판자이시며 구원자이신 하나님이십니다. 포도즙틀을 밟는 자처럼 붉은 옷을 입으신 모습은 원수들을 심판하시는 하나님의 공의로운 분노를 보여줍니다. 하나님께서는 홀로 포도즙틀을 밟으셨다고 말씀하십니다. 그 누구의 도움도 없이, 오직 당신의 팔로 심판을 행하시고 구원을 이루셨다는 선언입니다.\n\n이사야는 이제 하나님께서 이스라엘에게 베푸신 은혜의 역사를 회상합니다. 출애굽 때부터 지금까지 하나님께서는 "나의 백성이요 거짓을 행하지 아니하는 자녀"라 부르시며 그들의 구원자가 되어 주셨습니다. 백성들의 모든 환난에 함께하시고, 사랑과 자비로 그들을 품으시며, 날마다 그들을 업고 다니셨던 하나님의 신실하심이 아름답게 그려집니다.\n\n그러나 백성들은 이 은혜를 배반했습니다. 그들이 반역하여 하나님의 성령을 근심하게 하자, 사랑의 하나님께서 어쩔 수 없이 그들의 대적이 되셨습니다. 이 얼마나 가슴 아픈 전환입니까. 백성들은 이제야 모세 시대의 영광을 기억하며 탄식합니다. 홍해를 가르시고 광야에서 인도하셨던 그 하나님이 지금은 어디 계시냐고 울부짖습니다.\n\n이사야의 기도는 더욱 간절해집니다. "주는 우리 아버지시라"는 고백과 함께, 설령 아브라함과 이스라엘이 그들을 알아보지 못한다 할지라도 여호와만은 영원한 아버지요 구속자이심을 선포합니다. 비록 지금은 하나님의 다스림을 받지 못하는 자처럼, 그 이름으로 일컬음을 받지 못하는 자처럼 되었지만, 여전히 하나님께 매달리는 이사야의 믿음이 우리의 가슴을 울립니다. 심판 가운데서도 결코 포기할 수 없는 것은 하나님이 우리의 아버지라는 진리입니다.', E'오늘의 핵심\n하나님께서는 홀로 심판을 행하시는 공의로운 전사이시면서도, 동시에 백성들의 모든 환난에 함께하시는 자비로운 아버지이십니다.\n\n묵상 질문\n1. 하나님의 심판이 두렵기만 한가요, 아니면 그 안에서도 구원의 소망을 발견할 수 있나요?\n2. 내가 하나님의 성령을 근심하게 한 일은 없는지 돌아볼 때 무엇이 떠오르나요?\n3. 어려운 상황에서도 "주는 우리 아버지"라고 고백할 수 있는 믿음이 내게 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2027-12-31', E'영광과 평화의 청사진 (이사야 64장)', E'이사야 64장', E'이사야는 포로기의 어두운 현실 속에서 하나님께 간절히 부르짖고 있습니다. "원하건대 주는 하늘을 가르고 강림하시고"(사 64:1)라는 애타는 호소로 시작되는 이 기도는 과거 출애굽 때 시내산에서 보여주셨던 하나님의 위엄과 권능을 다시 한번 나타내 주시기를 간구하는 것입니다. 이스라엘 백성이 바벨론 포로로 끌려가고 예루살렘 성전이 파괴된 상황에서, 이사야는 하나님의 직접적인 개입만이 유일한 소망임을 고백하고 있습니다.\n\n그러나 이사야의 기도는 단순한 구원의 요청으로 끝나지 않습니다. 그는 이스라엘이 처한 비참한 현실의 원인을 정직하게 직시합니다. 백성들의 의는 "더러운 옷"과 같고, 그들은 "잎사귀 같이 시들어" 죄악의 바람에 몰려가고 있다고 고백합니다. 주의 이름을 부르는 자도, 스스로 분발하여 하나님을 붙잡는 자도 없는 영적 무기력의 상태를 솔직하게 인정하는 것입니다. 이는 회복의 첫걸음이 철저한 자기 성찰과 회개에서 시작됨을 보여줍니다.\n\n그럼에도 불구하고 이사야는 절망하지 않습니다. "그러나 여호와여, 이제 주는 우리 아버지시니이다"라는 고백은 심판 가운데서도 변하지 않는 하나님과의 관계를 붙잡는 믿음의 선언입니다. 토기장이와 진흙의 비유를 통해 창조주 하나님의 주권을 인정하면서도, 동시에 그분이 자기 백성을 버리지 않으실 것이라는 확신을 표현합니다. 예루살렘 성전이 불타고 거룩한 성읍들이 황폐해진 참담한 현실 속에서도, 이사야는 하나님의 자비와 언약적 신실하심에 호소하며 회복의 소망을 놓지 않습니다.', E'오늘의 핵심\n이사야는 철저한 죄의 고백과 함께 토기장이 되신 하나님께서 진흙 같은 백성을 다시 빚어주실 것을 간구하며, 심판 속에서도 언약적 관계를 붙잡는 믿음을 보여줍니다.\n\n묵상 질문\n1. 나는 어려운 상황에서 하나님의 개입을 간절히 구하면서도 내 죄를 정직하게 고백하고 있나요?\n2. "주는 우리 아버지"라는 이사야의 고백이 내게 주는 위로와 소망은 무엇인가요?\n3. 토기장이 되신 하나님께서 나를 새롭게 빚어주시기를 원하는 영역은 어디인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-01-01', E'영광과 평화의 청사진 (이사야 65장)', E'이사야 65장', E'하나님께서는 당신을 찾지도 않고 부르지도 않던 이들에게 먼저 손을 내미셨습니다. "나는 나를 구하지 아니하던 자에게 물음을 받았으며 나를 찾지 아니하던 자에게 찾아냄이 되었으며"(사 65:1)라는 하나님의 고백은 끊임없이 백성을 찾아가시는 그분의 사랑을 보여줍니다. 종일 손을 펴서 패역한 백성을 부르시는 하나님의 모습은 포기하지 않으시는 아버지의 마음을 그대로 드러냅니다.\n\n그러나 백성들은 동산에서 우상에게 제사하고, 무덤 사이에서 밤을 지내며, 부정한 음식을 먹으면서도 스스로를 거룩하다고 여기는 교만에 빠져 있었습니다. 이들의 위선적인 종교 행위는 하나님의 코에 연기가 되고 종일 타는 불이 되어 그분의 진노를 일으켰습니다. 형식적 종교와 실제 삶의 괴리, 자기 의로 가득한 그들의 모습은 오늘날 우리에게도 경고가 됩니다.\n\n하지만 하나님의 심판 속에서도 구원의 소망은 사라지지 않습니다. 포도송이에 즙이 있어 상하게 하지 않듯이, 하나님께서는 당신의 종들을 위하여 남은 자를 보존하실 것입니다. 야곱과 유다에게서 씨를 내어 약속의 땅을 기업으로 받을 자들을 세우시는 하나님의 신실하심이 여기에 나타납니다.\n\n이사야를 통해 선포되는 가장 놀라운 약속은 새 하늘과 새 땅의 창조입니다. 이전의 모든 고통과 슬픔이 잊혀지고, 예루살렘이 즐거운 성으로 변화되며, 우는 소리와 부르짖는 소리가 사라질 것입니다. 그곳에서는 수명이 연장되고, 수고의 열매를 온전히 누리며, 이리와 어린 양이 함께 뛰노는 평화의 나라가 펼쳐집니다. 부르기 전에 응답하시고 말을 마치기 전에 들으시는 하나님과의 친밀한 교제가 회복되는 것입니다.\n\n이 모든 약속은 단순히 미래의 소망만이 아닙니다. 오늘도 우리를 먼저 찾아오시고, 끝까지 사랑하시며, 새롭게 하시는 하나님의 은혜가 우리 삶 가운데 임하고 있음을 기억해야 합니다.', E'오늘의 핵심\n하나님께서는 당신을 찾지 않던 백성들에게 먼저 손을 내미시고, 심판 가운데서도 남은 자를 통한 구원과 새 하늘과 새 땅의 소망을 약속하십니다.\n\n묵상 질문\n1. 나를 먼저 찾아오신 하나님의 사랑을 어떻게 경험하고 있나요?\n2. 형식적 신앙생활과 진정한 거룩함의 차이를 어떻게 분별할 수 있을까요?\n3. 새 하늘과 새 땅의 소망이 오늘 나의 삶에 어떤 변화를 가져다줄까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-01-03', E'영광과 평화의 청사진 (이사야 66장)', E'이사야 66장', E'이사야서의 대미를 장식하는 66장은 하나님께서 원하시는 참된 예배가 무엇인지 분명하게 보여주고 있습니다. "하늘은 나의 보좌요 땅은 나의 발판이니"라는 선포로 시작되는 이 말씀은, 온 우주를 다스리시는 하나님 앞에서 인간이 지은 성전이나 제사가 얼마나 보잘것없는지를 깨닫게 합니다. 하나님께서 진정 원하시는 것은 화려한 성전 건물이나 많은 제물이 아니라, "마음이 가난하고 심령에 통회하며 내 말을 듣고 떠는 자"의 겸손한 마음이었습니다.\n\n당시 이스라엘 백성들은 겉으로는 제사를 드리면서도 실상은 우상숭배와 악행을 버리지 못하고 있었습니다. 그들의 제사는 형식만 남은 껍데기였고, 하나님께서는 이런 위선적인 예배를 살인이나 우상숭배와 다름없다고 책망하셨습니다. 진정한 예배는 삶의 변화와 순종이 뒤따라야 하는데, 그들은 여전히 자기 뜻대로 살면서 하나님의 부르심에는 응답하지 않았던 것입니다.\n\n그러나 이 엄중한 심판의 메시지 가운데서도 하나님의 구원 계획은 멈추지 않습니다. 시온은 진통 없이 아들을 낳을 것이며, 예루살렘은 어머니가 자녀를 위로하듯 백성을 위로할 것이라는 약속이 주어집니다. 이는 단순한 회복을 넘어선 새로운 창조의 역사를 예고하는 것이었습니다. 하나님께서는 "새 하늘과 새 땅"을 창조하실 것이며, 그때에는 모든 민족이 하나님께 나아와 예배하게 될 것입니다.\n\n특별히 주목할 점은 이방 민족들까지도 하나님의 구원에 참여하게 된다는 약속입니다. 다시스와 룻, 두발과 야완 같은 먼 나라들까지 하나님의 영광을 보게 될 것이며, 그들 중에서도 제사장과 레위인이 선택될 것이라는 말씀은 구원의 보편성을 보여줍니다. 이는 훗날 예수 그리스도를 통해 성취될 만민 구원의 청사진이었습니다.', E'오늘의 핵심\n하나님께서는 형식적인 종교 행위가 아닌 겸손하고 통회하는 마음의 예배를 원하시며, 새 하늘과 새 땅에서 모든 민족이 참된 예배자가 될 것을 약속하십니다.\n\n묵상 질문\n1. 내가 드리는 예배는 진정 마음을 다한 것인가요, 아니면 형식에 그치고 있나요?\n2. 하나님의 말씀 앞에 떠는 겸손한 마음을 가지고 있는지 돌아볼 때 무엇이 보이나요?\n3. 새 하늘과 새 땅의 소망이 오늘 나의 삶에 어떤 위로와 도전을 주고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-01-04', E'끌려간 남유다 백성에 대한 설득 (예레미야 2장)', E'예레미야 2장', E'예레미야는 하나님께서 주신 말씀을 예루살렘 백성들에게 전합니다. 하나님께서는 이스라엘과의 첫 사랑을 기억하시며, 광야에서 신부가 신랑을 따르듯 하나님을 따랐던 그 시절을 회상하십니다. 이스라엘은 하나님께 드려진 거룩한 첫 열매였고, 그들을 해치는 자는 누구든지 벌을 받았습니다. 그러나 지금 이스라엘은 완전히 달라졌습니다.\n\n하나님께서는 이스라엘의 변절을 두 가지 죄악으로 규정하십니다. "내 백성이 두 가지 악을 행하였나니 곧 그들이 생수의 근원되는 나를 버린 것과 스스로 웅덩이를 판 것인데 그것은 그 물을 가두지 못할 터진 웅덩이들이니라"(렘 2:13). 생수의 근원이신 하나님을 떠나 스스로 만든 우상을 섬기는 것은 터진 웅덩이에 물을 담으려는 어리석은 행위와 같습니다.\n\n이스라엘의 지도자들도 타락했습니다. 제사장들은 여호와를 찾지 않고, 율법을 다루는 자들은 하나님을 알지 못하며, 관리들은 하나님께 반역하고, 선지자들은 바알의 이름으로 예언합니다. 하나님께서 순전한 참 종자로 심으신 포도나무가 이방 포도나무의 악한 가지가 되어버린 것입니다.\n\n더욱 안타까운 것은 이스라엘이 자신들의 죄를 인정하지 않는다는 점입니다. 그들은 우상을 아버지라 부르고 돌을 향해 "너는 나를 낳았다"고 고백하면서도, 여전히 자신들은 더럽혀지지 않았다고 주장합니다. 환난이 닥치면 하나님께 구원을 요청하지만, 평안할 때는 하나님을 잊어버립니다. 처녀가 패물을 잊을 수 없고 신부가 예복을 잊을 수 없듯이, 하나님의 백성이 하나님을 잊는다는 것은 있을 수 없는 일입니다.\n\n하나님께서는 이스라엘의 회개를 간절히 원하십니다. 애굽과 앗수르를 의지하며 정치적 해결책을 찾아 헤매는 그들에게, 진정한 해결은 생수의 근원이신 하나님께로 돌아오는 것임을 깨닫기를 바라십니다.', E'오늘의 핵심\n하나님께서는 생수의 근원이신 자신을 버리고 터진 웅덩이 같은 우상을 섬기는 이스라엘의 영적 간음을 책망하시며, 그들이 회개하고 돌아오기를 간절히 원하십니다.\n\n묵상 질문\n1. 나는 생수의 근원이신 하나님보다 터진 웅덩이 같은 것들을 의지하고 있지는 않은가?\n2. 환난 때만 하나님을 찾고 평안할 때는 하나님을 잊어버리는 이스라엘의 모습이 나의 모습은 아닌가?\n3. 하나님과의 첫사랑을 회복하기 위해 내가 버려야 할 우상은 무엇인가?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-01-05', E'끌려간 남유다 백성에 대한 설득 (예레미야 3장)', E'예레미야 3장', E'예레미야 3장은 하나님과 이스라엘의 관계를 부부 관계에 비유하여 보여줍니다. 하나님께서는 이스라엘을 간음한 아내로, 자신을 버림받은 남편으로 묘사하시면서도 여전히 돌아오기를 간절히 바라시는 마음을 드러내십니다. \n\n북이스라엘이 우상숭배로 인해 앗수르에 멸망당한 것을 보고도 남유다는 교훈을 얻지 못했습니다. 오히려 "반역한 유다"는 "배역한 이스라엘"보다 더 악했다고 하나님께서는 평가하십니다. 형식적인 종교 개혁을 하면서도 진심으로 돌아오지 않았기 때문입니다. 높은 산과 푸른 나무 아래에서 행하는 우상숭배는 영적 간음이었고, 이는 언약 관계를 파기하는 배신 행위였습니다.\n\n그러나 놀랍게도 하나님께서는 "배역한 자식들아 돌아오라 나는 너희 남편임이라"(14절)고 말씀하십니다. 이혼서까지 주었던 이스라엘을 다시 받아주시겠다는 것입니다. 율법에 따르면 한 번 이혼한 아내가 다른 남자와 결혼했다가 다시 돌아오는 것은 가증한 일이었지만, 하나님의 사랑은 율법을 뛰어넘습니다. \n\n하나님께서는 회복의 약속을 구체적으로 제시하십니다. 마음에 합한 목자들을 세우시고, 예루살렘이 여호와의 보좌가 되며, 남북이 하나 되어 약속의 땅으로 돌아올 것입니다. 특히 언약궤를 더 이상 기억하지 않을 것이라는 말씀은 외적 종교에서 내적 신앙으로의 전환을 암시합니다. 이 모든 회복의 출발점은 "네 죄를 자복하라"(13절)는 하나님의 부르심에 응답하는 것입니다. 죄를 인정하고 돌아올 때, 하나님께서는 배역함을 고치시고 새로운 관계를 시작하십니다.', E'오늘의 핵심\n하나님께서는 영적 간음으로 떠난 이스라엘을 여전히 사랑하시며, 진정한 회개를 통해 돌아오기를 간절히 기다리십니다.\n\n묵상 질문\n1. 나는 형식적 신앙생활을 하면서도 진심으로 돌아왔다고 착각하고 있지는 않은가?\n2. 하나님의 용서가 율법을 넘어서는 은혜임을 깨달을 때 어떤 변화가 일어날까?\n3. "네 죄를 자복하라"는 부르심 앞에 내가 인정해야 할 것은 무엇인가?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-01-06', E'패역한 남유다 (예레미야 4장)', E'예레미야 4장', E'예레미야는 하나님의 간절한 호소로 시작됩니다. "이스라엘아 네가 돌아오려거든 내게로 돌아오라"(1절). 이 부르심에는 조건이 있습니다. 가증한 것을 버리고, 흔들리지 않으며, 진실과 정의와 공의로 살아야 한다는 것입니다. 하나님께서는 단순히 종교적 회개가 아니라 삶의 전면적인 변화를 요구하십니다. 특히 "너희 마음 가죽을 베고"(4절)라는 표현은 외적인 할례가 아닌 내면의 진정한 변화를 가리킵니다.\n\n그러나 백성의 완고함으로 인해 하나님의 심판이 선포됩니다. 북방에서 오는 재난은 사자처럼 맹렬하고, 회오리바람처럼 빠르게 다가올 것입니다. 예레미야는 이 심판의 광경을 미리 보며 고통스러워합니다. "슬프고 아프다 내 마음속이 아프고"(19절)라는 그의 탄식은 백성을 향한 하나님의 아픔을 대변합니다. 선지자는 하나님의 마음과 백성의 운명 사이에서 찢어지는 고통을 느끼고 있습니다.\n\n23-26절에 묘사된 심판의 광경은 창세기의 창조를 역행하는 듯합니다. "혼돈하고 공허하며 하늘에는 빛이 없으며"라는 표현은 창조 이전의 혼돈으로 돌아가는 것 같은 철저한 파괴를 보여줍니다. 그러나 27절에서 하나님은 놀라운 약속을 주십니다. "이 온 땅이 황폐할 것이나 내가 진멸하지는 아니할 것이며." 심판 속에서도 남은 자를 위한 하나님의 자비가 남아 있습니다.\n\n이 말씀은 오늘 우리에게도 동일하게 적용됩니다. 하나님께서는 형식적인 신앙이 아닌 마음의 진정한 변화를 원하십니다. 우리가 계속 하나님의 음성을 거부한다면, 그 결과는 피할 수 없는 심판입니다. 그러나 동시에 하나님은 회개하고 돌아오는 자들을 위해 은혜의 문을 열어두고 계십니다. 지금이라도 늦지 않았습니다. 우리 마음의 가죽을 베고 진정으로 하나님께 돌아가야 할 때입니다.', E'오늘의 핵심\n하나님은 형식적인 회개가 아닌 마음의 진정한 변화를 원하시며, 심판 중에도 완전한 멸망이 아닌 회복의 소망을 남겨두십니다.\n\n묵상 질문\n1. 내 신앙생활에서 마음의 할례가 필요한 영역은 무엇인가요?\n2. 하나님의 경고를 듣고도 변하지 않는 완고함이 내 안에 있지는 않나요?\n3. 심판의 메시지 속에서도 발견되는 하나님의 자비를 어떻게 경험하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-01-07', E'패역한 남유다 (예레미야 5장)', E'예레미야 5장', E'예레미야 5장은 예루살렘 멸망이 임박한 시점에서 하나님께서 왜 심판하실 수밖에 없는지를 낱낱이 드러냅니다. "너희는 예루살렘 거리로 빨리 다니며 그 넓은 거리에서 찾아보고 알라 너희가 만일 정의를 행하며 진리를 구하는 자를 한 사람이라도 찾으면 내가 이 성읍을 용서하리라"(렘 5:1). 소돔과 고모라를 연상시키는 이 말씀은 예루살렘의 영적 상태가 얼마나 심각한지를 보여줍니다. 하나님께서는 단 한 사람의 의인만 있어도 도시 전체를 용서하시겠다고 하셨지만, 그 한 사람조차 찾을 수 없었습니다.\n\n특히 충격적인 것은 지도자들의 타락입니다. 예레미야는 처음에 비천한 자들이 하나님의 길을 알지 못하는 것이라 생각하고 지도자들에게 갔습니다. 그러나 하나님의 법을 알아야 할 그들조차 "일제히 멍에를 꺾고 결박을 끊은" 상태였습니다. 영적 지도자들의 타락은 백성 전체를 어둠으로 인도했습니다. 선지자들은 거짓을 예언하고, 제사장들은 자기 권력으로 다스리며, 백성들은 그것을 좋게 여겼습니다.\n\n그런 가운데 하나님께서는 자연의 질서를 통해 자신의 주권을 상기시키십니다. 바다에 모래로 경계를 정하신 분, 이른 비와 늦은 비를 때를 따라 주시는 분이 바로 하나님이십니다. 그러나 백성들은 창조주 하나님을 경외하지 않았고, 오히려 피조물을 섬기며 살았습니다. 그들의 집에는 "새장에 새들이 가득함 같이" 속임이 가득했고, 고아와 과부의 송사를 공정하게 하지 않으면서도 번창하고 있었습니다.\n\n이 모든 것이 하나님의 마음을 아프게 했습니다. "내가 어찌 이 일들에 대하여 벌하지 아니하겠으며"라는 탄식은 심판이 하나님의 본심이 아님을 보여줍니다. 그럼에도 "그 때에도 내가 너희를 진멸하지는 아니하리라"는 약속은 심판 중에도 남겨두실 자비의 여지를 암시합니다. 오늘 우리 시대도 예루살렘과 다르지 않을 수 있습니다. 정의와 진리를 구하는 한 사람, 하나님을 진정으로 경외하는 그 한 사람이 바로 나부터 되어야 하지 않을까요.', E'오늘의 핵심\n하나님께서는 예루살렘에서 단 한 명의 의인만 있어도 용서하시겠다고 하셨지만, 지도자부터 백성까지 모두가 하나님을 떠나 있었고, 그럼에도 심판 중에 남은 자를 위한 자비를 예비하셨습니다.\n\n묵상 질문\n1. 하나님은 왜 단 한 사람의 의인만으로도 도시 전체를 용서하시려 하셨을까요?\n2. 내 삶과 우리 시대에서 정의와 진리를 막는 것은 무엇인가요?\n3. 심판 중에도 자비를 베푸시는 하나님께 나는 어떻게 응답할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-01-08', E'패역한 남유다 (예레미야 6장)', E'예레미야 6장', E'베냐민 자손들에게 예루살렘을 떠나라고 외치는 예레미야의 긴박한 경고로 시작되는 6장은 남유다의 최후가 임박했음을 보여줍니다. 북방에서 밀려오는 바벨론 군대의 침공이 목전에 이르렀지만, 예루살렘은 여전히 회개하지 않고 있었습니다. 하나님께서는 샘이 물을 솟구쳐냄같이 악을 드러내는 예루살렘의 모습을 한탄하시며, 마지막으로 "너는 훈계를 받으라"고 호소하십니다.\n\n예레미야를 통해 전해지는 하나님의 마음은 절박함 그 자체입니다. "옛적 길 곧 선한 길이 어디인지 알아보고 그리로 가라"(렘 6:16)는 권면은 출애굽 이후 하나님께서 이스라엘과 맺으신 언약의 길로 돌아오라는 간곡한 부르심이었습니다. 그 길은 나그네와 과부를 돌보고, 정의를 행하며, 하나님만을 섬기는 길이었습니다. 그러나 백성들의 대답은 차갑기만 했습니다. "우리는 그리로 가지 않겠노라"는 완고한 거부였습니다.\n\n가장 작은 자부터 큰 자까지 탐욕에 빠져 있고, 선지자와 제사장마저 거짓을 행하는 시대. 종교 지도자들은 "평강하다 평강하다" 하며 거짓 위로를 전했지만, 실상은 평강이 없었습니다. 그들은 가증한 일을 행하면서도 부끄러워할 줄 모르고, 시바에서 가져온 값비싼 유향으로 제사를 드리면 충분하다고 착각했습니다. 그러나 하나님께서는 그들의 형식적인 제사를 거절하셨습니다.\n\n예레미야는 금속을 제련하는 자로 비유되어 백성을 살피는 사명을 받았지만, 아무리 불에 달구어도 악한 찌꺼기가 제거되지 않는 은처럼, 백성들은 끝내 정결케 되지 않았습니다. 결국 그들은 "내버린 은"이라 불리게 될 운명에 처했습니다. 북방에서 오는 잔인한 군대의 포효 소리가 들려오는 가운데, 예루살렘의 운명은 이미 결정되어 가고 있었습니다.', E'오늘의 핵심\n하나님께서는 심판 직전까지도 "옛적 길 곧 선한 길"로 돌아오라고 호소하셨지만, 끝까지 거부하는 백성들을 향해 결국 심판을 선포하실 수밖에 없었습니다.\n\n묵상 질문\n1. 하나님께서 보여주신 "옛적 길 곧 선한 길"은 오늘 나에게 어떤 의미인가요?\n2. 형식적인 종교 행위로 진정한 회개를 대신하고 있지는 않은가요?\n3. 하나님의 훈계를 받아들이기 어려운 내 마음의 완고함은 무엇 때문일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-01-10', E'예레미야의 설득 (예레미야 7장)', E'예레미야 7장', E'예루살렘 성전은 유다 백성에게 거짓된 안전감을 주는 피난처가 되어 있었습니다. 하나님께서는 예레미야를 성전 문에 서게 하시고, 예배하러 오는 사람들에게 충격적인 메시지를 선포하게 하십니다. "여호와의 성전이라, 여호와의 성전이라, 여호와의 성전이라"(렘 7:4)는 주문처럼 반복되는 이 말은 백성들이 성전의 존재만으로 자신들이 안전하다고 착각하고 있음을 보여줍니다. 그들은 도둑질하고 살인하며 간음하고 거짓 맹세하면서도, 성전에 와서는 구원받았다고 선언하는 모순된 삶을 살고 있었습니다.\n\n하나님께서는 실로의 성소를 예로 드시며 경고하십니다. 한때 하나님의 임재가 머물던 실로가 이스라엘의 죄악으로 인해 폐허가 된 것처럼, 예루살렘 성전도 같은 운명을 맞게 될 것이라는 엄중한 심판의 메시지였습니다. 더욱 충격적인 것은 하나님께서 예레미야에게 이 백성을 위해 기도하지 말라고 명령하신 점입니다. 중보기도마저 거부하실 정도로 백성의 죄악이 극에 달했음을 보여주는 장면입니다.\n\n하나님께서 진정으로 원하신 것은 번제나 희생제물이 아니었습니다. 출애굽 당시부터 하나님께서 요구하신 것은 단 하나, "너희는 내 목소리를 들으라"는 순종이었습니다. 그러나 백성들은 조상 때부터 지금까지 계속해서 하나님의 음성에 등을 돌리고 악한 마음의 완악함을 따라 행했습니다. 힌놈의 골짜기에서 자녀들을 불태우는 가증한 우상숭배는 그들의 타락이 얼마나 깊은지를 보여주는 극단적인 증거였습니다. 이제 그곳은 ''죽임의 골짜기''가 되어 심판의 상징이 될 것입니다.', E'오늘의 핵심\n하나님께서는 형식적인 종교 행위가 아닌 진정한 순종을 원하시며, 성전의 존재 자체가 구원을 보장하지 않음을 엄중히 경고하십니다.\n\n묵상 질문\n1. 나는 혹시 교회 출석이나 종교적 행위만으로 안전하다고 착각하고 있지는 않나요?\n2. 하나님께서 내게 원하시는 진정한 순종은 무엇이며, 나는 그 음성을 듣고 있나요?\n3. 내 삶에서 하나님보다 더 의지하고 있는 거짓된 안전장치는 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-01-11', E'예레미야의 설득 (예레미야 8장)', E'예레미야 8장', E'예레미야 8장은 하나님의 심판이 얼마나 철저하게 임할 것인지를 보여줍니다. 심지어 무덤에 묻힌 자들의 뼈까지 꺼내어 우상들 앞에 흩어놓겠다는 선포는 고대 근동에서 가장 수치스러운 형벌이었습니다. 유다 백성들이 섬기던 해와 달과 별들, 그 우상들 앞에서 그들의 뼈가 거두어지지도 묻히지도 못한 채 분토처럼 버려질 것입니다.\n\n하나님은 예레미야를 통해 백성들의 완고함을 탄식하십니다. 넘어진 사람은 다시 일어나고, 길을 떠난 사람은 돌아오는 것이 자연스러운 이치인데, 유다 백성들은 거짓을 고집하며 돌아오기를 거부합니다. 심지어 철새들도 때를 알아 돌아오건만, 하나님의 백성은 여호와의 규례를 알지 못한다는 비유는 그들의 영적 무감각을 극명하게 드러냅니다.\n\n더욱 심각한 것은 종교 지도자들의 타락입니다. 서기관들은 거짓된 붓으로 율법을 왜곡하고, 선지자와 제사장들은 백성의 상처를 가볍게 여기며 "평강하다, 평강하다" 외칩니다. 그러나 진정한 평강은 없습니다. 그들은 가증한 일을 행하면서도 부끄러워할 줄 모르고, 탐욕에 눈이 멀어 있습니다.\n\n예레미야의 마음은 찢어집니다. "길르앗에는 유향이 있지 아니한가"라는 그의 탄식은 치료의 가능성은 있으나 백성들이 그것을 거부하는 비극을 보여줍니다. 추수 때가 지나고 여름이 다했으나 구원을 얻지 못했다는 백성들의 절망적인 외침과, 그들과 함께 상하여 슬퍼하는 예언자의 모습은 하나님의 아픈 마음을 대변합니다. 심판 가운데서도 백성을 향한 하나님의 사랑은 예레미야의 눈물을 통해 흐르고 있습니다.', E'오늘의 핵심\n유다 백성의 완고한 거부와 종교 지도자들의 타락 앞에서, 하나님은 철저한 심판을 선포하시면서도 예레미야의 눈물을 통해 여전히 아파하십니다.\n\n묵상 질문\n1. 나는 넘어졌을 때 일어나고, 잘못된 길에서 돌아올 줄 아는 사람인가요?\n2. 내 삶에서 "평강하다"고 자위하며 외면하고 있는 영적 상처는 무엇인가요?\n3. 길르앗의 유향처럼 내게 주어진 은혜의 기회를 놓치고 있지는 않나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-01-12', E'주의 계명을 떠난 이스라엘', E'예레미야 9장', E'이스라엘 백성은 하나님 앞에서 그 길을 바르게 하지 않고, 오히려 거짓말을 하여 도둑질하고 있습니다. 또한 하나님을 섬기지 않고 바알을 숭배합니다. 하나님께서는 예레미야에게 이스라엘 백성을 위하여 간구하지도 말라 하십니다. 예레미야 9장은 예레미야와 하나님과의 대화를 통해, 예레미야가 이스라엘 백성으로 인해 얼마나 마음 아파하고 있는지를 보여주고 있습니다. 예레미야는 할 수만 있다면 다른 곳에 가서 살고 싶다고 말합니다. 자신이 목놓아 외치는 하나님의 말씀은 듣지 않고, 거짓과 죄악에 더 깊이 빠져드는 백성을 목도할 수밖에 없는 자신의 현실이 너무도 고통스럽기 때문입니다. 그러나 이스라엘을 외면할 수 없는 것이 하나님의 마음이듯이, 예레미야 또한 하나님의 말씀을 전하는 일과 민족을 살리기 위해 몸부림치는 일을 포기할 수 없었습니다. 이스라엘 백성은 임박한 멸망의 시간이 다가오자, 그들 나름대로의 지혜와 용맹과 부를 그 해결책으로 삼으려 합니다. 하지만 그런 것들은 시시각각 다가오는 멸망의 날에 그들을 구원할 수 없습니다. 유일한 해결책은 하나님을 바로 알고 그분이 원하시는 사랑과 정의와 공의를 행하는 것입니다.', E'오늘의 핵심\n회개할 줄 모르는 백성, 하나님을 떠나 돌아오지 않는 백성을 향해 예레미야는 마음을 찢는 아픔을 호소합니다.\n\n묵상 질문\n1. 하나님은 왜 거짓과 죄악에 빠진 백성을 그렇게 오랫동안 인내하시나요?\n2. 내가 주변 사람들의 죄악을 볼 때, 예레미야처럼 아파하고 있나요?\n3. 하나님의 뜻을 외치는 일이 힘들 때, 내가 어떻게 믿음을 지켜나갈 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-01-13', E'약속을 깨뜨린 이스라엘 (예레미야 10장)', E'예레미야 10장', E'예레미야는 참 하나님과 헛된 우상의 본질적 차이를 선명하게 대조시켜 보여줍니다. 당시 유다 백성들은 주변 강대국들의 화려한 우상 숭배 문화에 깊이 매료되어 있었습니다. 바벨론과 앗수르의 거대한 신전들, 정교하게 만들어진 신상들, 그리고 이방인들이 하늘의 징조를 보며 두려워하는 모습은 유다 백성들에게도 영향을 미치고 있었습니다.\n\n예레미야는 이러한 우상의 실체를 낱낱이 폭로합니다. 아무리 화려하게 금과 은으로 꾸미고, 다시스의 은박과 우바스의 금으로 장식해도, 그것은 결국 삼림에서 벤 나무에 불과하다는 것입니다. 기술공의 손재주로 아무리 정교하게 만들어도 말도 못하고 걸어다니지도 못해서 사람이 메고 다녀야 하는 무력한 존재일 뿐입니다. 이러한 우상은 화를 주거나 복을 줄 능력이 전혀 없습니다.\n\n반면 여호와 하나님은 "참 하나님이시요 살아 계신 하나님이시요 영원한 왕"이십니다. 그분은 권능으로 땅을 지으시고, 지혜로 세계를 세우시며, 명철로 하늘을 펴신 창조주이십니다. 그분이 목소리를 내시면 하늘에 많은 물이 생기고, 땅 끝에서 구름이 오르며, 비를 위한 번개가 치는 것입니다. 이것이 바로 참 하나님과 헛된 우상의 결정적 차이입니다.\n\n그러나 유다의 지도자들은 이 명백한 진리를 외면했습니다. "목자들은 어리석어 여호와를 찾지 아니하므로"라는 예레미야의 탄식은 영적 지도자들의 실패를 가리킵니다. 그들이 하나님을 떠나자 양 떼인 백성들도 흩어지게 되었습니다. 이제 북방에서 들려오는 큰 소리, 곧 바벨론의 침략 소식이 임박했습니다.\n\n이러한 위기 속에서 예레미야는 놀라운 신앙고백을 합니다. "사람의 길이 자신에게 있지 아니하니 걸음을 지도함이 걷는 자에게 있지 아니하니이다"(렘 10:23). 인간은 스스로의 힘으로는 올바른 길을 갈 수 없으며, 오직 하나님의 인도하심이 필요하다는 깨달음입니다. 그래서 그는 하나님께 징계하시되 너그러이 하시기를 간구합니다. 이는 심판을 피하려는 것이 아니라, 하나님의 은혜로운 징계를 통해 회복되기를 바라는 간절한 기도입니다.', E'오늘의 핵심\n예레미야는 생명 없는 우상과 살아계신 창조주 하나님을 대조하면서, 인간의 길은 오직 하나님의 인도하심 속에서만 바르게 될 수 있음을 고백합니다.\n\n묵상 질문\n1. 내 삶에서 하나님보다 더 의지하고 있는 ''현대의 우상''은 무엇인가요?\n2. 살아계신 하나님의 능력을 일상에서 어떻게 경험하고 있나요?\n3. "사람의 길이 자신에게 있지 않다"는 고백이 내게 주는 의미는 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-01-14', E'약속을 깨뜨린 이스라엘 (예레미야 11장)', E'예레미야 11장', E'하나님께서는 예레미야에게 언약의 말씀을 유다와 예루살렘 백성에게 전하라고 명하십니다. 이 언약은 하나님께서 이스라엘 백성을 애굽의 쇠풀무에서 구원하실 때 맺으신 것으로, "너희는 내 목소리를 순종하고 나의 모든 명령을 따라 행하라"(렘 11:4)는 내용이었습니다. 하나님과 백성 사이의 관계는 이 언약에 기초하고 있었으며, 순종을 통해 약속의 땅에서 복을 누리도록 하셨습니다.\n\n그러나 백성들은 조상들의 악한 길로 돌아가 다른 신들을 섬기며 언약을 파기했습니다. 하나님께서는 애굽에서 인도해 내신 날부터 끊임없이 경고하셨지만, 그들은 각자 악한 마음의 완악함을 따라 행했습니다. 예루살렘 거리마다 바알 제단이 세워졌고, 유다의 신들은 성읍 수만큼 많아졌습니다. 언약의 파기는 단순한 불순종이 아니라 하나님과의 관계를 완전히 거부하는 반역이었습니다.\n\n이에 하나님께서는 피할 수 없는 재앙을 선포하시며, 백성들이 부르짖어도 듣지 않으시겠다고 하십니다. 더 나아가 예레미야에게 이 백성을 위해 기도하지 말라고 명하십니다. 중보기도마저 거절하시는 하나님의 모습은 심판이 이미 확정되었음을 보여줍니다. 백성들이 섬기던 우상들은 재앙의 때에 아무런 도움이 되지 못할 것입니다.\n\n예레미야가 이런 메시지를 전하자 그의 고향 아나돗 사람들이 그를 죽이려 합니다. 그들은 "여호와의 이름으로 예언하지 말라"며 위협했습니다. 진리를 전하는 자가 오히려 박해받는 아이러니한 상황입니다. 하나님께서는 예레미야를 보호하시며 아나돗에 심판을 선언하십니다. 언약의 말씀을 거부하고 하나님의 사자를 핍박하는 것은 결국 스스로를 멸망으로 이끄는 길이었습니다.', E'오늘의 핵심\n하나님께서는 언약을 파기하고 우상을 섬기는 백성에게 피할 수 없는 심판을 선포하시며, 중보기도마저 거절하실 정도로 그들의 반역이 극에 달했음을 보여주십니다.\n\n묵상 질문\n1. 하나님과 맺은 언약을 일상에서 어떻게 기억하고 순종하며 살아가고 있나요?\n2. 내 삶에 하나님보다 더 의지하고 있는 ''우상''은 무엇인가요?\n3. 진리의 말씀이 불편하게 들릴 때, 나는 어떤 반응을 보이나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-01-15', E'약속을 깨뜨린 이스라엘 (예레미야 12장)', E'예레미야 12장', E'악인의 형통함에 대한 예레미야의 탄식은 모든 시대 신앙인들이 품어온 질문을 대변합니다. 선지자는 하나님의 의로우심을 전제하면서도, 악한 자의 길이 형통하고 반역한 자가 평안한 현실에 대해 솔직하게 묻습니다. 그들은 입술로는 하나님을 가까이하지만 마음은 멀리 떠나 있으며, 오히려 번성하여 열매를 맺고 있습니다. 이러한 부조리한 현실 앞에서 예레미야는 정의로운 심판을 간구합니다.\n\n하나님의 대답은 예레미야에게 더 큰 시련을 준비하라는 도전으로 시작됩니다. "네가 보행자와 함께 달려도 피곤하면 어찌 능히 말과 경주하겠느냐"는 말씀은 지금의 고난이 앞으로 올 더 큰 시련의 전조임을 암시합니다. 심지어 그의 형제들과 아버지의 집마저도 그를 배신할 것이라는 경고가 이어집니다. 선지자의 길은 외로움과 배신의 길이었습니다.\n\n하나님께서는 당신의 백성을 향한 아픔을 토로하십니다. 사랑하는 소유를 원수의 손에 넘기셨다는 표현은 심판자로서의 하나님이 아닌, 배신당한 아버지의 마음을 보여줍니다. 이스라엘은 숲속의 사자처럼 하나님을 대적했고, 많은 목자들이 하나님의 포도원을 짓밟아 황무지로 만들었습니다. 밀을 심어도 가시를 거두는 헛된 수고는 하나님과의 관계가 단절된 삶의 결과였습니다.\n\n그러나 심판의 메시지 속에서도 회복의 소망이 빛납니다. 하나님께서는 악한 이웃 나라들을 뽑아내신 후, 다시 불쌍히 여기셔서 각자의 기업으로 인도하시겠다고 약속하십니다. 더 놀라운 것은 이방 민족들까지도 여호와의 이름으로 맹세하며 하나님의 백성의 도를 배우면 그들도 하나님의 백성 가운데 세움을 받으리라는 약속입니다. 심판 너머에 있는 하나님의 긍휼과 회복의 계획이 선포되고 있습니다.', E'오늘의 핵심\n예레미야의 정직한 탄식과 하나님의 응답은 고난 중에도 더 큰 시련을 준비해야 하는 선지자의 소명과, 심판 너머에 있는 하나님의 회복 계획을 보여줍니다.\n\n묵상 질문\n1. 악인이 형통할 때 나는 하나님께 어떻게 질문하고 기도하나요?\n2. 더 큰 시련이 올 것을 알면서도 믿음의 길을 걸어갈 용기가 있나요?\n3. 심판 속에서도 회복을 계획하시는 하나님의 마음을 어떻게 이해하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-01-17', E'약속을 깨뜨린 이스라엘 (예레미야 13장)', E'예레미야 13장', E'여호야김 시대, 하나님께서는 예레미야에게 독특한 상징적 행동을 명령하십니다. 베 띠를 사서 허리에 띠되 물에 적시지 말고, 그것을 유브라데 강가 바위 틈에 감추라는 것이었습니다. 예레미야가 순종하여 띠를 감추었다가 여러 날 후에 하나님의 명령에 따라 다시 가서 확인해보니, 그 띠는 완전히 썩어서 쓸 수 없게 되어 있었습니다. 이 상징적 행동은 유다와 예루살렘의 운명을 보여주는 것이었습니다. 본래 띠가 사람의 허리에 밀착되어 있듯이, 이스라엘과 유다는 하나님께 속하여 그분의 백성이 되고 그분의 이름과 명예와 영광이 되도록 부르심을 받았습니다. 그러나 그들이 하나님의 말씀을 듣지 않고 다른 신들을 따라 섬기며 절하였기에, 썩은 띠처럼 아무 쓸모없게 되리라는 경고였습니다.\n\n이어서 하나님께서는 포도주로 가득 찬 가죽부대의 비유를 통해 심판의 메시지를 전하십니다. 모든 주민과 왕들, 제사장들과 선지자들이 포도주에 취한 것처럼 정신을 잃고 서로 충돌하여 상하게 될 것이며, 하나님께서는 불쌍히 여기지도 아끼지도 않고 그들을 멸하실 것이라고 선포하십니다. 예레미야는 간절히 호소합니다. 어둠이 임하기 전에, 발이 어두운 산에 걸려 넘어지기 전에, 교만을 버리고 하나님께 영광을 돌리라고 말입니다. 그러나 백성이 듣지 않으면 선지자의 심령은 은밀한 곳에서 울 수밖에 없고, 여호와의 양 떼가 사로잡혀 가는 것을 보며 통곡할 수밖에 없다고 토로합니다.\n\n특별히 하나님께서는 구스인이 피부색을 바꿀 수 없고 표범이 반점을 변하게 할 수 없듯이, 악에 익숙해진 백성이 스스로 선을 행할 수 없음을 지적하십니다. 오직 하나님의 은혜로만 변화가 가능한데, 그들은 하나님을 잊고 거짓을 신뢰했습니다. 그 결과 사막 바람에 날리는 검불처럼 흩어지게 될 것이며, 그들의 수치가 드러나게 될 것입니다. 하나님께서는 예루살렘을 향해 "네가 얼마나 오랜 후에야 정결하게 되겠느냐"라고 탄식하시며, 여전히 돌이킬 기회를 주고 계십니다.', E'오늘의 핵심\n썩은 베 띠의 상징을 통해 하나님께서는 그분을 떠난 백성의 쓸모없음을 보여주시며, 동시에 아직도 돌이킬 기회가 있음을 간절히 호소하십니다.\n\n묵상 질문\n1. 내가 하나님께 밀착되어 있지 않고 멀어진 영역은 무엇인가요?\n2. 악에 익숙해져서 스스로 바꿀 수 없는 나의 습관이나 죄는 무엇인가요?\n3. 하나님께서 내게 주시는 회개의 기회를 놓치고 있지는 않나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-01-18', E'마음을 돌이키라 (예레미야 14장)', E'예레미야 14장', E'예레미야 14장은 유다 땅을 덮친 극심한 가뭄의 장면으로 시작됩니다. 귀인들이 사환을 보내 물을 구하려 해도 우물은 말라 있고, 빈 그릇을 안고 돌아온 사환들은 부끄러워 머리를 가립니다. 들판의 암사슴은 풀이 없어 갓 낳은 새끼마저 버리고, 들나귀들은 벗은 산 위에서 승냥이처럼 헐떡입니다. 온 땅이 갈라지고 생명이 메말라가는 처참한 광경입니다.\n\n이 가뭄은 단순한 자연재해가 아니었습니다. 하나님께서는 "그들이 어그러진 길을 사랑하여 그들의 발을 멈추지 아니하므로"(14:10) 이제 그들의 죄를 기억하시고 벌하신다고 말씀하십니다. 백성들이 계속해서 잘못된 길로 나아가며 하나님을 떠났기에, 하나님께서도 그들의 기도를 듣지 않겠다고 선언하십니다.\n\n더욱 비극적인 것은 이런 위기 상황에서 거짓 선지자들이 활개를 쳤다는 사실입니다. 그들은 "칼도 기근도 오지 않을 것이며 확실한 평강이 있으리라"(14:13)고 선포했습니다. 하나님께서 보내지도 않으셨는데 하나님의 이름으로 예언하며, 거짓 계시와 자기 마음의 속임수로 백성을 현혹시켰습니다. 진짜 위기의 순간에 가장 위험한 것은 바로 이런 거짓된 평안의 메시지입니다.\n\n그러나 본문 후반부에서 예레미야와 백성들의 간절한 기도가 이어집니다. "우리의 악과 우리 조상의 죄악을 인정하나이다"(14:20)라는 고백과 함께, 하나님의 언약을 기억해 달라고 부르짖습니다. 비록 하나님께서 심판을 선언하셨지만, 백성들은 여전히 "우리 하나님 여호와"만이 비를 내리실 수 있는 분임을 고백합니다.\n\n가뭄으로 메마른 땅처럼, 우리 삶에도 아무것도 채워지지 않는 메마름의 시간이 찾아옵니다. 그때 우리는 쉬운 위로나 거짓된 평안에 기대기보다, 혹시 내가 걷고 있는 길이 하나님께서 기뻐하시는 길인지 진지하게 돌아봐야 합니다. 하나님의 징계는 우리를 망하게 하려는 것이 아니라, 다시 하나님께로 돌아오게 하려는 사랑의 부르심입니다.', E'오늘의 핵심\n극심한 가뭄을 통해 하나님께서는 어그러진 길을 멈추지 않는 백성을 징계하시지만, 그 징계 속에는 여전히 돌아오기를 기다리시는 하나님의 마음이 담겨 있습니다.\n\n묵상 질문\n1. 내 삶의 메마른 영역이 혹시 하나님께서 주시는 경고의 신호는 아닐까요?\n2. 위기 속에서 거짓된 평안의 메시지에 귀 기울이고 있지는 않은지 점검해 보셨나요?\n3. 하나님께서 기뻐하시는 길로 돌아서기 위해 오늘 무엇을 결단하시겠습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-01-19', E'마음을 돌이키라 (예레미야 15장)', E'예레미야 15장', E'"모세와 사무엘이 내 앞에 섰다 할지라도 내 마음은 이 백성을 향할 수 없나니"(렘 15:1). 하나님의 이 선언은 이스라엘을 향한 심판이 얼마나 확정적인지를 보여줍니다. 모세는 금송아지 사건 때 백성을 위해 중보했고, 사무엘은 미스바에서 회개하는 백성을 위해 기도했던 위대한 중보자들이었습니다. 그런데 하나님은 이들이 나선다 해도 마음을 돌이키지 않겠다고 하십니다. 죽을 자는 죽음으로, 칼을 받을 자는 칼로, 기근을 당할 자는 기근으로, 포로 될 자는 포로로 나아가리라는 네 가지 운명이 선포됩니다.\n\n이 엄중한 심판 선언 속에서 예레미야는 깊은 고뇌에 빠집니다. "내게 재앙이로다 나의 어머니여"라고 탄식하며, 돈을 빌려주지도 빌리지도 않았는데 모든 사람이 자신을 저주한다고 호소합니다. 하나님의 말씀을 전하는 예언자의 삶이 얼마나 고독하고 힘든지를 보여주는 장면입니다. 그는 하나님의 말씀을 얻어먹고 기쁨과 즐거움을 누렸지만, 동시에 하나님의 분노로 가득 차서 홀로 앉아야 했습니다. 예언자는 하나님과 백성 사이에서 찢기는 존재였습니다.\n\n그런데 예레미야가 "주께서는 내게 대하여 물이 말라서 속이는 시내 같으시리이까"라고 원망할 때, 하나님은 놀라운 약속을 주십니다. "네가 만일 돌아오면 내가 너를 다시 이끌어 내 앞에 세울 것이며... 너는 나의 입이 될 것이라." 심지어 예언자조차도 끊임없이 하나님께로 돌아와야 하며, 헛된 것을 버리고 귀한 것을 말해야 한다는 것입니다. 하나님은 그를 "견고한 놋 성벽"으로 세우겠다고 약속하십니다.\n\n이 말씀은 오늘 우리에게도 깊은 울림을 줍니다. 때로 우리도 하나님의 뜻을 따르다가 고독하고 지칠 때가 있습니다. 주변의 이해를 받지 못하고, 심지어 하나님마저 침묵하시는 것 같을 때가 있습니다. 그러나 하나님은 우리가 계속해서 그분께로 돌아오기를 원하십니다. 헛된 것에서 돌이켜 귀한 것을 붙들 때, 우리도 이 시대를 위한 견고한 놋 성벽이 될 수 있습니다.', E'오늘의 핵심\n하나님은 심판을 선언하시면서도 예언자가 돌이키면 다시 세우시겠다고 약속하시며, 그를 백성을 위한 견고한 놋 성벽으로 만드시겠다고 하십니다.\n\n묵상 질문\n1. 내가 하나님의 뜻을 따르면서 경험한 고독과 어려움은 무엇인가요?\n2. "헛된 것을 버리고 귀한 것을 말한다"는 것이 내 삶에서 어떤 의미일까요?\n3. 하나님께서 나를 이 시대의 ''견고한 놋 성벽''으로 세우신다면, 나는 무엇을 지켜야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-01-20', E'마음을 돌이키라 (예레미야 16장)', E'예레미야 16장', E'하나님은 예레미야에게 참으로 이해하기 어려운 명령을 내리십니다. 결혼하지 말고, 자녀를 두지 말며, 초상집과 잔칫집에도 가지 말라는 것입니다. 이는 단순한 개인적 금욕이 아니라, 예레미야의 삶 자체가 하나님의 메시지가 되어야 했기 때문입니다. 임박한 심판이 너무나 확실하여, 가정을 이루는 것조차 무의미한 시대가 되었음을 선지자의 삶을 통해 보여주신 것입니다.\n\n백성들이 "우리가 무슨 죄를 지었습니까?"라고 묻자, 하나님은 그들의 조상들이 하나님을 버리고 다른 신들을 섬겼을 뿐 아니라, "너희가 너희 조상들보다 더욱 악을 행하였도다"(16:12)라고 지적하십니다. 세대를 거듭할수록 죄악이 더해졌고, 각자가 악한 마음의 완악함을 따라 행하며 하나님께 순종하지 않았습니다. 그 결과 약속의 땅에서 쫓겨나 낯선 땅에서 우상을 섬기게 될 것이라는 선언은, 출애굽의 은혜를 완전히 뒤집는 저주였습니다.\n\n그런데 이 무서운 심판의 선언 가운데서도 하나님의 약속은 빛납니다. 북방 땅과 흩어진 모든 나라에서 다시 인도하여 내실 것이며, 그때는 출애굽보다 더 큰 구원의 역사로 기억될 것이라고 하십니다(16:14-15). 심판은 끝이 아니라 새로운 시작을 위한 과정이었습니다. 어부와 포수를 보내어 숨은 죄인들을 찾아내시는 것도, 궁극적으로는 "여호와 나의 힘, 나의 요새, 환난날의 피난처"(16:19)라는 참된 고백에 이르게 하려는 것입니다.\n\n특별히 주목할 것은 이방 민족들까지도 "우리 조상들의 계승한 바는 허망하고 거짓되고 무익한 것뿐이라"(16:19)고 고백하며 하나님께 나아올 것이라는 약속입니다. 이스라엘의 회복은 단순한 민족의 복귀를 넘어, 온 세계가 참 하나님을 알게 되는 우주적 구원의 서막이 될 것입니다. 하나님의 심판은 파멸이 목적이 아니라, "내 이름이 여호와인 줄 알게 하리라"(16:21)는 궁극적인 계시를 위한 것입니다.', E'오늘의 핵심\n하나님께서는 심판을 통해서라도 백성들이 헛된 우상을 버리고 참되신 여호와만을 힘과 요새로 고백하게 하시며, 이를 통해 열방까지도 하나님께 돌아오는 구원의 역사를 이루십니다.\n\n묵상 질문\n1. 내 삶에서 대를 이어 내려온 잘못된 신앙의 유산은 무엇이며, 어떻게 끊어낼 수 있을까요?\n2. 하나님의 징계가 두렵기만 한 것이 아니라 회복을 위한 사랑임을 깨달은 적이 있나요?\n3. "여호와 나의 힘, 나의 요새"라는 고백이 진실하게 나오려면 무엇을 내려놓아야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-01-21', E'남유다의 죄 (예레미야 17장)', E'예레미야 17장', E'유다의 죄는 금강석 끝 철필로 그들의 마음 판에 새겨져 있었습니다. 이는 단순히 표면적인 잘못이 아니라, 그들의 존재 깊숙이 뿌리박힌 죄성을 보여줍니다. 높은 언덕의 푸른 나무 곁에 세운 제단들과 아세라 상들은 하나님께 드려야 할 예배가 얼마나 심각하게 왜곡되었는지를 드러냅니다. 이처럼 깊이 새겨진 죄로 인해 하나님께서는 그들의 재산과 보물, 그리고 약속의 기업까지도 원수의 손에 넘기실 것을 선포하십니다.\n\n이어서 하나님은 두 가지 상반된 길을 선명하게 대조하십니다. 사람을 의지하며 육신의 힘을 믿는 자는 사막의 떨기나무와 같아서, 좋은 일이 와도 알아보지 못하고 메마른 광야에서 고독하게 살아갑니다. 반면 여호와를 의지하고 의뢰하는 자는 물가에 심긴 나무처럼 뿌리를 깊이 내려 가뭄이 와도 잎이 청청하고 열매가 그치지 않습니다. 이 비유는 단순한 축복과 저주의 대비가 아니라, 삶의 근원을 어디에 두느냐에 따른 필연적 결과를 보여줍니다.\n\n"만물보다 거짓되고 심히 부패한 것은 마음이라"(렘 17:9)는 선언은 인간 본성에 대한 하나님의 진단입니다. 그러나 절망으로 끝나지 않습니다. 심장을 살피시고 폐부를 시험하시는 하나님께서는 생수의 근원이 되어 주십니다. 예레미야가 "나를 고치소서 그리하시면 내가 낫겠나이다"라고 고백하듯, 치유와 구원의 능력은 오직 여호와께만 있습니다.\n\n마지막으로 하나님은 안식일 준수라는 구체적인 순종의 영역을 제시하십니다. 안식일에 짐을 지고 성문을 드나드는 일상의 모습은 하나님의 거룩함보다 경제적 이익을 우선시하는 그들의 가치관을 보여줍니다. 안식일을 거룩히 지키는 것은 단순한 율법 준수가 아니라, 창조주 하나님의 주권을 인정하고 그분께 삶의 우선순위를 드리는 신앙고백이었습니다. 순종하면 다윗 왕조와 예루살렘 성의 영속을, 불순종하면 꺼지지 않는 심판의 불을 예고하시는 하나님의 말씀은 오늘 우리에게도 동일한 선택을 요구합니다.', E'오늘의 핵심\n금강석 철필로 새겨진 것처럼 깊이 뿌리박힌 죄성에도 불구하고, 하나님은 여전히 생수의 근원이 되어 주시며 회개와 순종의 길을 열어두십니다.\n\n묵상 질문\n1. 내 마음 판에 하나님보다 더 깊이 새겨진 것은 무엇이며, 그것을 어떻게 하나님께 내어드릴 수 있을까요?\n2. 사막의 떨기나무처럼 사람과 세상의 힘을 의지하며 살고 있지는 않습니까? 물가의 나무처럼 하나님께 뿌리내리려면 어떤 변화가 필요할까요?\n3. 오늘날 내 삶에서 안식일의 정신을 실천한다는 것은 구체적으로 어떤 모습일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-01-22', E'남유다의 죄 (예레미야 18장)', E'예레미야 18장', E'하나님께서 예레미야를 토기장이의 집으로 보내십니다. 녹로(물레) 위에서 토기장이가 진흙으로 그릇을 빚다가 마음에 들지 않자 다시 뭉개어 새로운 그릇을 만드는 모습은, 이스라엘을 향한 하나님의 주권적 통치를 생생하게 보여주는 비유였습니다. "진흙이 토기장이의 손에 있음 같이 너희가 내 손에 있느니라"(렘 18:6)는 선포는 창조주이신 하나님께서 피조물인 인간과 민족의 운명을 주관하시는 절대 주권자이심을 분명히 드러냅니다.\n\n토기장이의 비유가 전하는 놀라운 소식은 하나님의 심판이 조건적이라는 사실입니다. 하나님은 어느 민족을 멸하려 하셨다가도 그들이 악에서 돌이키면 재앙의 뜻을 돌이키시고, 반대로 건설하고 심으려 하셨다가도 그들이 악을 행하면 복의 뜻을 돌이키신다고 말씀하십니다. 이는 하나님의 변덕이 아니라 인간의 자유의지와 책임을 존중하시는 하나님의 은혜로운 성품을 보여줍니다. 심판의 선포 속에서도 회개의 문은 여전히 열려 있었던 것입니다.\n\n그러나 유다 백성의 반응은 충격적이었습니다. "이는 헛되니 우리는 우리의 계획대로 행하며 우리는 각기 악한 마음이 완악한 대로 행하리라"(렘 18:12). 토기장이의 손에서 부드럽게 빚어질 수 있는 진흙이 되기를 거부하고, 스스로 굳어진 돌이 되기를 선택한 것입니다. 레바논의 만년설이 녹지 않고 산에서 흘러내리는 찬물이 마르지 않는 것처럼, 당연한 자연의 이치를 거스르는 이상한 일이 벌어진 것입니다.\n\n이런 백성의 완악함은 예레미야를 향한 적대감으로 이어집니다. 그들은 제사장의 율법과 지혜자의 책략과 선지자의 말씀이 끊어지지 않을 것이라며, 예레미야의 경고를 무시하고 오히려 그를 해하려는 음모를 꾸밉니다. 자신들의 종교 체제가 견고하다고 믿었지만, 정작 하나님의 살아있는 말씀을 거부하는 모순에 빠진 것입니다.\n\n토기장이이신 하나님은 오늘도 우리를 그분의 손에서 빚으시길 원하십니다. 때로는 우리의 계획이 무너지고 다시 시작해야 할 때가 있습니다. 그것은 실패가 아니라 더 나은 그릇으로 빚어지는 은혜의 과정입니다. 중요한 것은 ''우리의 계획대로'' 고집하며 굳어진 진흙이 되지 않는 것입니다.', E'오늘의 핵심\n토기장이이신 하나님은 회개하고 돌이키는 자를 새롭게 빚으시지만, 완악하게 자기 뜻을 고집하는 자는 심판하십니다.\n\n묵상 질문\n1. 내 삶에서 하나님의 손길로 다시 빚어져야 할 부분은 무엇입니까?\n2. ''우리의 계획대로 행하리라''는 유다의 완악함이 내 안에도 있지는 않습니까?\n3. 토기장이이신 하나님의 주권을 온전히 신뢰하며 순종할 준비가 되어 있습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-01-24', E'남유다의 죄 (예레미야 19장)', E'예레미야 19장', E'토기장이의 집에서 돌아온 예레미야에게 하나님은 더 충격적인 상징 행동을 명령하십니다. 옹기를 사서 백성의 지도자들과 함께 힌놈의 아들 골짜기로 가라는 것이었습니다. 이곳은 예루살렘 남쪽에 위치한 계곡으로, 훗날 ''게헨나''라 불리며 지옥의 상징이 되는 곳입니다. 그곳에서 이루어진 가장 끔찍한 일은 자녀를 불태워 바알에게 바치는 인신제사였습니다. 하나님은 이런 장소에서 심판의 메시지를 선포하게 하신 것입니다.\n\n예레미야가 들고 간 옹기는 이미 구워져서 완성된 토기였습니다. 18장에서 토기장이가 진흙을 다시 빚는 모습이 회개의 기회를 보여주었다면, 19장의 깨진 옹기는 돌이킬 수 없는 심판을 의미합니다. "사람이 토기장이의 그릇을 한 번 깨뜨리면 다시 완전하게 할 수 없나니"(19:11)라는 선언은 유다의 운명이 봉인되었음을 보여줍니다. 백성들이 무죄한 자녀들의 피로 이 땅을 더럽혔듯이, 이제 그들 자신이 이곳에서 멸망당할 것이라는 엄중한 경고였습니다.\n\n더욱 충격적인 것은 심판의 내용입니다. 포위된 성읍 안에서 극심한 기근으로 인해 부모가 자녀를 잡아먹는 비극이 일어날 것이라는 예언은 신명기의 저주가 그대로 실현되는 것을 보여줍니다. 바알에게 자녀를 바쳤던 그들이 이제는 생존을 위해 자녀를 먹게 되는 아이러니한 심판이었습니다. \n\n이 무거운 메시지를 전한 예레미야는 성전 뜰로 돌아와 모든 백성에게 재앙을 선포합니다. 그들이 목을 곧게 하여 하나님의 말씀을 듣지 않았기 때문이라는 것입니다. 완고함이 깨진 옹기처럼 회복 불가능한 파멸로 이어진다는 엄중한 경고였습니다.\n\n오늘 우리도 깨지기 전의 옹기처럼 아직 기회가 있을 때, 목을 곧게 하지 말고 하나님의 음성에 귀 기울여야 합니다. 내 계획과 고집을 내려놓고 토기장이 되신 하나님의 손에 나를 맡길 때, 깨어짐이 아닌 새로운 빚음을 경험할 수 있을 것입니다.', E'오늘의 핵심\n하나님은 깨진 옹기를 통해 완고한 백성에게 임할 돌이킬 수 없는 심판을 선포하시며, 목을 곧게 하여 말씀을 거부하는 자의 최후를 경고하십니다.\n\n묵상 질문\n1. 내 삶에서 하나님의 말씀에 목을 곧게 하고 있는 영역은 무엇입니까?\n2. 깨지기 전 옹기처럼 아직 회개의 기회가 있을 때 돌이켜야 할 죄는 무엇입니까?\n3. 토기장이 되신 하나님께 온전히 내 삶을 맡기고 있습니까, 아니면 내 계획을 고집하고 있습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-01-25', E'남유다의 죄 (예레미야 20장)', E'예레미야 20장', E'예레미야의 예언 사역이 극한의 고통에 이르는 순간을 성경은 숨기지 않고 보여줍니다. 성전 총감독 바스훌은 예레미야를 때리고 나무 고랑에 채워 하룻밤 동안 베냐민 문 위층에 가두어 둡니다. 선지자가 공개적으로 모욕당하고 고문당하는 장면입니다. 다음날 풀려난 예레미야는 바스훌에게 새로운 이름을 선포합니다. "마골밋사빕" - 사방이 두려움이라는 뜻입니다. 하나님을 대적한 자가 스스로 두려움의 근원이 되고, 그 두려움 속에서 멸망할 것이라는 무서운 심판의 선언이었습니다.\n\n그런데 이어지는 예레미야의 고백은 우리를 놀라게 합니다. "여호와여 주께서 나를 권유하시므로 내가 그 권유를 받았사오며"(렘 20:7). 하나님께 붙들린 자의 솔직한 탄식이 쏟아집니다. 말씀을 전할 때마다 조롱과 모욕을 당하니 차라리 입을 다물고 싶지만, 그러면 마음속에 불이 붙는 것 같아 견딜 수 없다고 고백합니다. 하나님의 말씀이 그의 골수에 사무쳐 있기 때문입니다. 예언자는 말씀을 전하면 고통스럽고, 전하지 않으면 더 고통스러운 이중의 아픔 속에 있었습니다.\n\n예레미야의 고백은 극단으로 치닫습니다. 자신이 태어난 날을 저주하며, 차라리 태중에서 죽었더라면 좋았을 것이라고 절규합니다. 욥의 탄식을 연상시키는 이 처절한 고백은 하나님의 종이 겪는 실존적 고통의 깊이를 보여줍니다. 그러나 주목할 것은 이런 극한의 고통 속에서도 예레미야가 하나님을 떠나지 않았다는 점입니다. 오히려 "두려운 용사 같으신" 여호와가 자신과 함께하심을 고백하며, 그분의 공의로운 심판을 구합니다.\n\n오늘날 우리도 신앙 때문에 조롱받거나 불이익을 당할 때가 있습니다. 직장에서 신앙의 가치관을 지키려다 소외되거나, 믿지 않는 가족들 사이에서 외로움을 느낄 수도 있습니다. 그럴 때 예레미야의 정직한 고백이 우리에게 위로가 됩니다. 하나님께서는 우리의 솔직한 탄식과 아픔을 다 아시며, 그 고통 중에도 함께하시는 분이십니다. 말씀에 붙들린 삶이 때로는 무겁지만, 그 말씀이 우리 안에 꺼지지 않는 불이 되어 끝까지 믿음의 길을 걷게 하실 것입니다.', E'오늘의 핵심\n하나님의 말씀에 붙들린 예레미야는 극심한 고통 속에서도 그 말씀을 전하기를 멈출 수 없었고, 정직한 탄식 가운데서도 하나님을 신뢰했습니다.\n\n묵상 질문\n1. 신앙 때문에 조롱이나 어려움을 당할 때, 나는 예레미야처럼 하나님께 솔직하게 내 아픔을 고백하고 있습니까?\n2. 하나님의 말씀이 내 안에서 꺼지지 않는 불처럼 타오르는 경험을 해본 적이 있습니까?\n3. 극한의 고통 속에서도 "두려운 용사 같으신" 하나님이 나와 함께하심을 신뢰할 수 있습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-01-26', E'예레미야의 설득 (예레미야 21장)', E'예레미야 21장', E'남유다의 운명이 풍전등화와 같은 위기에 놓였습니다. 바벨론 왕 느부갓네살의 군대가 예루살렘을 포위하자 시드기야 왕은 예레미야에게 사람을 보내어 하나님께서 기적으로 구원해 주시기를 간청합니다. 지금까지 하나님의 말씀을 무시해 왔던 왕이 급박한 상황에 처하자 선지자를 찾은 것입니다. 그러나 예레미야의 대답은 왕이 기대했던 것과는 전혀 달랐습니다. 하나님께서 오히려 바벨론 군대와 함께 유다를 치실 것이며, 성읍 안에 있는 자들은 칼과 기근과 전염병으로 죽게 될 것이라는 충격적인 선포였습니다.\n\n하나님께서는 유다 백성 앞에 두 길을 제시하십니다. 성읍에 남아 있으면 죽음이요, 나가서 바벨론에 항복하면 생명을 보전할 수 있다는 것입니다. 이는 민족적 자존심을 버리고 하나님의 심판을 겸허히 받아들이라는 요구였습니다. 예레미야는 이 메시지가 얼마나 받아들이기 어려운지 알았지만, 하나님의 뜻을 그대로 전할 수밖에 없었습니다. "내가 나의 얼굴을 이 성읍으로 향함은 복을 내리기 위함이 아니요 화를 내리기 위함이라"(렘 21:10)는 말씀은 하나님의 단호한 결정을 보여줍니다.\n\n그럼에도 하나님께서는 다윗의 집에 마지막 권고를 주십니다. 정의롭게 판결하고 억압받는 자를 구하라는 것입니다. 비록 심판이 결정되었지만, 회개와 순종의 여지는 아직 남아 있었습니다. 예레미야의 예언은 단순한 멸망의 선포가 아니라 하나님의 주권에 순복하고 그분의 길을 따르라는 간절한 호소였습니다. 하나님께서는 심판 중에서도 생명의 길을 열어두시는 분이십니다.', E'오늘의 핵심\n하나님께서는 유다의 완악함에 대해 바벨론을 통한 심판을 선포하시면서도, 그분의 주권에 순복하는 자에게는 생명의 길을 열어두십니다.\n\n묵상 질문\n1. 위기의 순간에 하나님께 나아가지만 여전히 내 뜻대로 응답받기를 원할 때가 있지 않나요?\n2. 하나님의 뜻이 내 기대와 다를 때, 어떻게 그분의 주권을 인정하고 순종할 수 있을까요?\n3. 오늘 내게 주어진 상황 속에서 하나님이 열어두신 ''생명의 길''은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-01-27', E'예레미야의 설득 (예레미야 22장)', E'예레미야 22장', E'예레미야는 하나님의 명령을 받아 왕궁으로 내려가 유다 왕과 그의 신하들에게 정의와 공의의 메시지를 선포합니다. 왕실이 걸어야 할 길은 명확했습니다. 탈취당한 자를 압박자의 손에서 건지고, 이방인과 고아와 과부를 보호하며, 무죄한 피를 흘리지 않는 것이었습니다. 하나님께서는 이러한 말씀에 순종하면 다윗 왕조가 계속될 것이라 약속하셨지만, 불순종하면 왕궁이 황폐하게 될 것이라 경고하셨습니다.\n\n예레미야는 요시야의 뒤를 이은 왕들에 대한 심판의 메시지를 전합니다. 애굽으로 끌려간 여호아하스(살룸), 불의와 탐욕으로 백향목 궁전을 짓던 여호야김, 그리고 바벨론에 포로로 잡혀갈 여호야긴(고니야)까지, 각 왕들의 운명이 선포됩니다. 특별히 여호야김에 대해서는 그의 아버지 요시야와 대조되는 평가가 내려집니다. 요시야는 정의와 공의를 행하며 가난한 자와 궁핍한 자를 변호했는데, 하나님께서는 바로 이것이 "나를 앎"이라고 말씀하십니다. \n\n여호야긴에 대한 예언은 더욱 비극적입니다. 그는 마치 "천하고 깨진 그릇"처럼 버려져 바벨론으로 끌려갈 것이며, 그의 후손 중에는 다윗의 왕위에 앉을 사람이 없을 것이라는 선고가 내려집니다. 하나님께서 세우신 다윗 왕조가 왕들의 불순종으로 인해 끊어지게 되는 것입니다. 이러한 심판의 선포는 단순히 정치적 실패에 대한 것이 아니라, 하나님과의 언약을 저버리고 우상을 섬긴 영적 배반에 대한 필연적인 결과였습니다.', E'오늘의 핵심\n하나님께서는 유다 왕들에게 정의와 공의를 행하라고 명하셨지만, 그들의 불순종으로 인해 다윗 왕조는 심판받게 됩니다. 참된 왕은 가난한 자를 돌보는 것이 곧 하나님을 아는 것임을 보여줍니다.\n\n묵상 질문\n1. 하나님이 원하시는 지도자의 모습은 어떤 것이며, 나는 내 자리에서 정의와 공의를 실천하고 있나요?\n2. 요시야처럼 가난한 자를 돌보는 것이 하나님을 아는 것이라면, 오늘 내가 돌봐야 할 이웃은 누구인가요?\n3. 불순종의 결과로 찾아오는 하나님의 심판을 피하려면, 지금 내가 돌이켜야 할 것은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-01-28', E'예레미야의 설득 (예레미야 23장)', E'예레미야 23장', E'남유다의 지도자들은 양 떼를 돌보는 목자가 아니라 오히려 양 떼를 흩어지게 하는 악한 목자가 되어버렸습니다. 하나님께서는 이들의 악행에 대해 준엄한 심판을 선포하십니다. 백성을 인도해야 할 왕과 제사장, 선지자들이 간음과 거짓을 일삼으며 악을 행하는 자들의 손을 강하게 하고 있었습니다. 특히 거짓 선지자들은 하나님의 말씀이 아닌 자기 마음에서 나온 헛된 환상을 전하며 백성들에게 거짓된 평안을 약속했습니다.\n\n이러한 절망적인 상황 속에서도 하나님은 새로운 희망의 메시지를 선포하십니다. 다윗의 후손 가운데서 의로운 가지를 일으키실 것이며, 그가 왕이 되어 지혜롭게 다스리며 정의와 공의를 행할 것이라고 약속하십니다. 이 메시아의 통치 아래서 유다는 구원을 받고 이스라엘은 평안히 거할 것이며, 그의 이름은 "여호와 우리의 공의"라 불릴 것입니다. 흩어진 양 떼를 모으시고 참된 목자를 세우시겠다는 이 약속은 예수 그리스도를 통해 성취될 구원의 청사진이었습니다.\n\n예레미야는 거짓 선지자들의 실체를 폭로합니다. 그들은 하나님의 회의에 참여한 적도 없으면서 마치 하나님의 말씀을 받은 것처럼 행세했습니다. 하나님의 말씀은 불같이 타오르고 바위를 부수는 방망이 같은 능력이 있는데, 거짓 선지자들의 말은 겨와 같이 무가치한 것이었습니다. 하나님께서는 천지에 충만하신 분이시므로 그 누구도 하나님 앞에서 자신을 숨길 수 없으며, 모든 거짓과 악행은 반드시 심판받게 될 것입니다.', E'오늘의 핵심\n하나님은 악한 지도자들을 심판하시고 다윗의 후손 가운데서 의로운 왕 메시아를 세우셔서 흩어진 백성을 모으시고 정의와 공의로 다스리실 것을 약속하십니다.\n\n묵상 질문\n1. 내가 맡은 자리에서 선한 목자의 역할을 감당하고 있는지 돌아보고 있나요?\n2. 거짓된 평안의 메시지와 하나님의 참된 말씀을 어떻게 분별할 수 있을까요?\n3. 메시아이신 예수님의 정의와 공의가 내 삶에 어떻게 나타나고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-01-29', E'바벨론 포로로 끌려간 남유다 백성 (예레미야 24장)', E'예레미야 24장', E'바벨론의 느부갓네살 왕이 유다 왕 여고냐와 고관들, 그리고 기술자들을 예루살렘에서 바벨론으로 끌고 간 후, 하나님께서는 예레미야에게 특별한 환상을 보여주십니다. 성전 앞에 놓인 두 광주리의 무화과, 하나는 처음 익은 듯 극히 좋은 무화과요, 다른 하나는 먹을 수 없을 정도로 나쁜 무화과였습니다. 이 환상을 통해 하나님께서는 당시 유다 백성이 이해할 수 없었던 신비를 계시하십니다.\n\n예루살렘에 남아 있던 사람들은 포로로 끌려간 동포들을 보며 자신들이 하나님의 심판을 피했다고 생각했을 것입니다. 시드기야 왕과 그의 고관들, 그리고 애굽으로 도피한 자들까지도 자신들이 더 나은 선택을 했다고 여겼을 것입니다. 그러나 하나님의 관점은 완전히 달랐습니다. 바벨론에 끌려간 포로들이야말로 좋은 무화과였고, 예루살렘에 남은 자들이 오히려 나쁜 무화과였던 것입니다.\n\n하나님께서는 갈대아 땅으로 보낸 유다 포로들을 "잘 돌볼 것"이라고 약속하십니다. 그들을 다시 이 땅으로 인도하여 세우고 심으실 것이며, 무엇보다 "여호와인 줄 아는 마음"을 주셔서 전심으로 돌아오게 하실 것입니다. 이것이야말로 진정한 회복의 약속입니다. 반면 예루살렘에 남은 자들에게는 환난과 수치, 조롱과 저주가 임할 것입니다. 하나님의 심판을 피하려 애굽으로 도망친 자들도 예외가 아닙니다.\n\n이 무화과 환상은 우리에게 중요한 진리를 가르쳐줍니다. 하나님의 징계는 때로 구원의 통로가 되며, 안전해 보이는 곳이 오히려 멸망의 자리가 될 수 있다는 것입니다. 포로로 끌려가는 고난의 길이 하나님께서 예비하신 회복의 길이었고, 예루살렘에 남아 있는 안락함이 도리어 심판의 자리였습니다. 하나님께서는 바벨론이라는 낯선 땅에서 당신의 백성을 새롭게 빚으시고, 참된 신앙을 회복시키실 계획을 갖고 계셨던 것입니다.', E'오늘의 핵심\n하나님께서는 바벨론 포로들을 좋은 무화과로, 예루살렘에 남은 자들을 나쁜 무화과로 보시며, 고난의 자리가 오히려 회복과 구원의 길임을 보여주십니다.\n\n묵상 질문\n1. 내가 피하고 싶은 고난의 자리가 혹시 하나님의 훈련 장소는 아닐까요?\n2. 겉으로 안전해 보이는 선택이 하나님의 뜻과 다를 때 순종할 수 있나요?\n3. 하나님께서 내 삶에 허락하신 ''바벨론''에서 어떤 믿음의 열매를 맺고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-01-31', E'바벨론 포로로 끌려간 남유다 백성 (예레미야 25장)', E'예레미야 25장', E'유다 왕 여호야김 넷째 해는 바벨론 왕 느부갓네살의 즉위 원년과 일치합니다. 이때 하나님께서는 예레미야를 통해 유다의 운명을 결정하는 중대한 메시지를 선포하십니다. 예레미야는 23년이라는 긴 세월 동안 하나님의 말씀을 전했지만, 백성들은 끝내 순종하지 않았습니다. 하나님께서는 수많은 선지자들을 보내셨고, 악한 길에서 돌이키면 조상들에게 약속하신 땅에 영원히 거하게 하시겠다고 말씀하셨습니다. 그러나 백성들은 우상 숭배를 멈추지 않았고, 오히려 손으로 만든 것들로 하나님의 노여움을 일으켰습니다.\n\n이제 하나님의 심판이 선포됩니다. 북방의 모든 종족과 바벨론 왕 느부갓네살이 하나님의 도구가 되어 유다를 치게 될 것입니다. 기쁨의 소리, 신랑 신부의 소리, 일상의 평화로운 소리가 모두 사라지고, 이 땅은 70년 동안 황폐한 폐허가 될 것입니다. 그러나 하나님의 공의는 바벨론에게도 임할 것입니다. 70년이 지나면 바벨론도 그들의 죄악으로 인해 심판받아 영원한 폐허가 될 것입니다.\n\n예레미야는 하나님의 진노의 잔을 받아 모든 나라에게 마시게 하는 상징적 환상을 봅니다. 예루살렘과 유다를 시작으로 애굽, 블레셋, 에돔, 모압, 암몬, 그리고 먼 나라들까지 모두가 이 진노의 잔을 마셔야 합니다. 하나님의 심판은 자신의 백성에게서 시작되어 온 세상으로 확대됩니다. "내 이름으로 일컬음을 받는 성에서부터 재앙 내리기를 시작하였은즉"(렘 25:29)이라는 말씀처럼, 하나님은 먼저 자기 백성을 심판하심으로써 그 공의로우심을 나타내십니다. 이는 하나님께서 온 세상의 심판자이시며, 그 누구도 하나님의 공의에서 벗어날 수 없음을 보여줍니다.', E'오늘의 핵심\n하나님께서는 23년 동안의 인내와 경고 후에 유다에 70년 포로기를 선포하시며, 이 심판은 예루살렘에서 시작되어 온 세상으로 확대됩니다.\n\n묵상 질문\n1. 하나님께서 23년이라는 긴 시간 동안 말씀하셨는데도 듣지 않는 백성의 모습이 오늘날 우리와 얼마나 닮아 있을까요?\n2. 하나님의 심판이 자기 백성에게서 먼저 시작된다는 사실이 우리에게 주는 경고는 무엇입니까?\n3. 70년이라는 구체적인 기간을 정하신 하나님의 은혜와 공의를 어떻게 이해해야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-01', E'이스라엘의 회복에 대한 약속 (예레미야 32장)', E'예레미야 32장', E'유다의 마지막 왕 시드기야는 바벨론에 의해 세워진 왕이었으나, 바벨론의 지배에서 벗어나려는 헛된 희망으로 반역을 시도했습니다. 그 결과 느부갓네살의 군대가 예루살렘을 포위하고 있는 긴박한 상황이 전개되었습니다. 이때 선지자 예레미야는 왕궁의 시위대 뜰에 감금되어 있었는데, 이는 그가 예루살렘의 멸망과 시드기야의 포로 됨을 예언했기 때문입니다.\n\n바로 이 절망적인 상황에서 하나님께서는 예레미야에게 놀라운 명령을 하십니다. 숙부의 아들 하나멜이 찾아와 아나돗에 있는 밭을 사라고 제안할 때, 그것을 사들이라는 것이었습니다. 예레미야는 은 17세겔을 달아 주고 정식으로 매매 증서를 작성하여 바룩에게 맡깁니다. 곧 바벨론에 의해 멸망할 땅의 부동산을 사는 이 행위는 상식적으로 이해할 수 없는 일이었습니다.\n\n그러나 이 상징적 행동은 하나님의 회복 약속을 담고 있었습니다. "사람이 이 땅에서 집과 밭과 포도원을 다시 사게 되리라"(렘 32:15)는 말씀처럼, 징계는 영원하지 않으며 회복의 날이 반드시 온다는 것을 보여주는 예언적 행동이었습니다. 예레미야의 기도는 이 약속의 근거가 하나님의 전능하심에 있음을 고백합니다. 천지를 창조하신 하나님께는 불가능한 일이 없으시기 때문입니다.\n\n하나님께서는 이스라엘의 죄악을 낱낱이 지적하시면서도, 동시에 놀라운 회복의 약속을 주십니다. 흩어진 백성을 다시 모으시고, 한 마음과 한 길을 주셔서 영원한 언약 관계를 맺으시겠다는 것입니다. 절망의 한복판에서 선포된 이 희망의 메시지는 하나님의 심판이 징계를 위한 것이지 멸절을 위한 것이 아님을 분명히 보여줍니다.', E'오늘의 핵심\n예루살렘 멸망이 임박한 절망적 상황에서도 하나님께서는 예레미야를 통해 회복의 확실한 약속을 주시며, 심판 너머에 있는 구원의 계획을 보여주십니다.\n\n묵상 질문\n1. 절망적인 상황에서도 하나님의 약속을 믿고 행동하는 믿음이 내게 있습니까?\n2. 하나님의 징계 속에서도 그분의 사랑과 회복의 계획을 발견할 수 있나요?\n3. 오늘 나에게 주시는 하나님의 약속은 무엇이며, 그것을 어떻게 붙잡겠습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-02', E'이스라엘의 회복에 대한 약속 (예레미야 33장)', E'예레미야 33장', E'예레미야가 여전히 시위대 뜰에 갇혀 있을 때, 여호와의 말씀이 두 번째로 그에게 임했습니다. 바벨론 군대가 예루살렘을 포위하고 있는 절망적인 상황에서도 하나님께서는 놀라운 약속의 말씀을 전하셨습니다. "너는 내게 부르짖으라 내가 네게 응답하겠고 네가 알지 못하는 크고 은밀한 일을 네게 보이리라"(렘 33:3). 이는 단순한 위로가 아니라 하나님께서 준비하신 구체적인 회복의 청사진이었습니다.\n\n하나님께서는 먼저 현실을 직시하게 하십니다. 예루살렘의 가옥과 왕궁이 무너지고, 거리에는 시체가 가득한 참혹한 광경을 보여주십니다. 이는 백성들의 악행으로 인한 필연적인 결과였습니다. 그러나 하나님의 말씀은 여기서 멈추지 않습니다. "그러나 보라"라는 전환점과 함께 놀라운 회복의 비전이 펼쳐집니다. 하나님께서는 이 성읍을 치료하고 고치시며, 평안과 진실이 풍성함을 약속하십니다.\n\n특별히 주목할 것은 이 회복이 단순한 물리적 재건에 그치지 않는다는 점입니다. 하나님께서는 백성들을 그들의 모든 죄악에서 정결하게 하시고 사하실 것을 약속하십니다. 황폐하여 사람도 짐승도 없다던 유다 성읍들과 예루살렘 거리에 다시 즐거워하는 소리, 기뻐하는 소리, 신랑과 신부의 소리가 들릴 것입니다. 감사제를 드리는 자들의 찬양이 성전에 울려 퍼질 것입니다.\n\n더 나아가 하나님께서는 다윗 언약의 영원성을 확증하십니다. 다윗의 보좌에 앉을 왕이 끊어지지 않을 것이며, 레위 제사장들의 직분도 계속될 것입니다. 이 약속의 확실성을 하나님께서는 낮과 밤의 언약, 천지의 법칙에 비유하여 설명하십니다. 해가 뜨고 지는 것처럼, 계절이 바뀌는 것처럼 확실한 약속이라는 것입니다. 심판의 어둠 속에서도 하나님의 신실하신 사랑은 변함이 없으며, 그분의 구원 계획은 반드시 성취될 것임을 보여줍니다.', E'오늘의 핵심\n하나님께서는 심판의 한복판에서도 회복의 약속을 주시며, 그 약속은 천지의 법칙처럼 확실하고 영원합니다.\n\n묵상 질문\n1. 절망적인 상황 속에서도 하나님께 부르짖을 때 응답하시는 그분의 신실하심을 경험한 적이 있나요?\n2. 내 삶의 황폐한 영역을 하나님께서 어떻게 치료하고 회복시키실 것을 기대하고 있나요?\n3. 하나님의 변치 않는 약속을 붙잡고 오늘 내가 할 수 있는 믿음의 선택은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-03', E'포위 중 항복을 위한 설득 (예레미야 34장)', E'예레미야 34장', E'바벨론의 느부갓네살 왕이 예루살렘을 포위하고 있을 때, 하나님께서는 예레미야를 통해 시드기야 왕에게 운명적인 메시지를 전하셨습니다. 예루살렘의 함락은 이미 정해진 일이며, 시드기야는 바벨론으로 끌려갈 것이라는 선고였습니다. 그러나 하나님께서는 동시에 자비로운 약속도 주셨습니다. 시드기야가 칼에 죽지 않고 평안히 죽을 것이며, 왕의 예우를 받으며 장사될 것이라는 것입니다. 이는 항복을 통해서라도 생명을 보존하시려는 하나님의 은혜였습니다.\n\n이러한 위기 상황에서 시드기야 왕과 백성들은 하나님 앞에서 특별한 계약을 맺었습니다. 히브리 노예들을 해방시키기로 한 것입니다. 이는 단순한 사회 개혁이 아니라 하나님의 율법에 대한 순종의 표현이었습니다. 출애굽 당시 하나님께서는 이스라엘 백성에게 동족을 영구히 종으로 삼지 말고 7년째 되는 해에는 자유를 주라고 명령하셨습니다. 그러나 오랜 세월 이 규정은 무시되어 왔습니다. 위기의 순간에 백성들은 비로소 하나님의 뜻을 기억하고 실천에 옮긴 것입니다.\n\n그러나 이들의 회개는 오래가지 못했습니다. 위기가 잠시 완화되자 그들은 마음을 바꾸어 해방시켰던 노예들을 다시 불러들여 종으로 삼았습니다. 이는 하나님과의 언약을 정면으로 배반하는 행위였습니다. 하나님께서는 이들의 위선적인 행동에 대해 엄중한 심판을 선포하셨습니다. "너희가 형제들에게 자유를 선포하지 않았으니, 내가 너희에게 칼과 전염병과 기근의 자유를 주겠다"는 역설적인 심판의 말씀은 그들의 불순종이 가져올 비참한 결과를 보여줍니다.\n\n특히 주목할 점은 그들이 언약을 맺을 때 행했던 의식입니다. 송아지를 둘로 쪼개고 그 사이를 지나가는 고대의 언약 의식은 "이 언약을 어기면 이 송아지처럼 되리라"는 엄숙한 맹세였습니다. 그런데 그들은 스스로 맺은 이 언약을 어김으로써 자신들의 운명을 결정지었습니다. 하나님께서는 인간의 자유 의지를 존중하시지만, 그 선택에 따른 책임도 분명히 물으십니다.', E'오늘의 핵심\n하나님께서는 위기 상황에서도 순종의 기회를 주시지만, 형식적이고 일시적인 회개가 아닌 진실하고 지속적인 순종을 원하십니다.\n\n묵상 질문\n1. 위기의 순간에만 하나님을 찾고 평안할 때는 잊어버리는 내 모습은 없나요?\n2. 하나님과 맺은 약속을 성실히 지키고 있는지 돌아볼 때입니다. 어떤 약속들이 있었나요?\n3. 진정한 회개는 행동의 변화로 나타납니다. 내 삶에서 바뀌어야 할 것은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-04', E'포위 중 항복을 위한 설득 (예레미야 35장)', E'예레미야 35장', E'예레미야 35장은 여호야김 시대로 시간을 거슬러 올라가, 레갑 사람들의 순종을 통해 이스라엘의 불순종을 대조적으로 보여줍니다. 하나님께서는 예레미야에게 레갑 사람들을 성전으로 데려와 포도주를 권하라고 명하십니다. 그러나 레갑 사람들은 선조 요나답의 명령을 철저히 지켜 포도주를 거절합니다. 그들은 약 250년 전 선조가 명령한 대로 포도주를 마시지 않고, 집도 짓지 않으며, 농사도 짓지 않고 장막에서 살아왔습니다. 바벨론의 침략으로 예루살렘에 피난 와 있는 상황에서도 그들의 신념은 변하지 않았습니다.\n\n이 사건은 하나님께서 이스라엘 백성에게 주시는 강력한 교훈이었습니다. 레갑 사람들은 인간 선조의 명령도 이토록 철저히 지키는데, 이스라엘은 창조주 하나님의 말씀을 끊임없이 거역해 왔습니다. 하나님께서는 선지자들을 계속 보내시며 악한 길에서 돌이켜 우상을 버리라고 호소하셨지만, 백성들은 귀를 기울이지 않았습니다. 레갑 사람들의 순종은 이스라엘의 완고한 불순종을 더욱 부각시킵니다. 결국 하나님께서는 말씀을 듣지도 응답하지도 않는 유다와 예루살렘에 선포하신 모든 재앙을 내리시겠다고 선언하십니다. \n\n그러나 레갑 사람들에게는 놀라운 약속이 주어집니다. 그들의 신실한 순종으로 인해 "레갑의 아들 요나답에게서 내 앞에 설 사람이 영원히 끊어지지 아니하리라"(렘 35:19)는 축복을 받게 됩니다. 이는 순종의 귀한 열매이자, 하나님께서 신실함을 얼마나 귀하게 여기시는지를 보여주는 증거입니다. 인간의 명령도 이렇게 지킬 수 있다면, 하물며 생명의 근원이신 하나님의 말씀은 얼마나 더 소중히 여기고 순종해야 하겠습니까.', E'오늘의 핵심\n하나님께서는 레갑 사람들의 철저한 순종을 통해 이스라엘의 완고한 불순종을 대조적으로 드러내시며, 순종하는 자에게 주시는 영원한 축복을 보여주십니다.\n\n묵상 질문\n1. 나는 하나님의 말씀을 레갑 사람들이 선조의 명령을 지킨 것처럼 신실하게 순종하고 있나요?\n2. 시대의 흐름과 상황의 압박 속에서도 변하지 않는 신앙의 원칙을 지키고 있나요?\n3. 내 삶에서 하나님보다 더 중요하게 여기며 순종하는 것은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-05', E'포위 중 항복을 위한 설득 (예레미야 36장)', E'예레미야 36장', E'유다 왕 여호야김 제4년, 하나님께서는 예레미야에게 특별한 명령을 내리십니다. 요시야 왕 때부터 지금까지 이스라엘과 유다에게 주신 모든 말씀을 두루마리에 기록하라는 것이었습니다. 이는 단순한 기록 보존이 아니라 유다 백성이 재난의 경고를 듣고 악한 길에서 돌이키게 하려는 하나님의 간절한 마음이었습니다.\n\n예레미야는 서기관 바룩을 불러 하나님의 말씀을 받아쓰게 합니다. 당시 예레미야는 어떤 이유로든 성전에 출입이 금지된 상태였기에, 바룩이 대신 금식일에 성전에서 두루마리를 낭독하게 됩니다. 제5년 9월, 온 백성이 금식을 선포했을 때 바룩은 성전 뜰의 서기관 그마랴의 방에서 예레미야의 말씀을 낭독했습니다.\n\n이 소식이 왕궁의 고관들에게 전해지자, 그들은 바룩을 불러 다시 한 번 듣기를 원했습니다. 말씀을 들은 고관들은 놀라며 이를 왕에게 보고해야 한다고 판단했습니다. 동시에 그들은 예레미야와 바룩에게 숨으라고 권했는데, 이는 왕의 반응을 어느 정도 예상했기 때문으로 보입니다.\n\n겨울 궁전에서 화로 앞에 앉아 있던 여호야김 왕은 여후디가 두루마리를 낭독할 때마다 서너 쪽씩 면도칼로 베어 화로에 던져 태워버렸습니다. 이는 하나님의 말씀에 대한 노골적인 거부였습니다. 엘라단과 들라야, 그마랴 같은 고관들이 만류했지만 왕은 듣지 않았고, 오히려 예레미야와 바룩을 체포하라고 명령했습니다. 그러나 하나님께서 그들을 숨기셨습니다.\n\n두루마리가 불탄 후 하나님은 예레미야에게 다시 말씀하셨습니다. 새 두루마리에 이전의 모든 말씀을 다시 기록하되, 여호야김에 대한 심판도 추가하라는 것이었습니다. 여호야김의 후손은 다윗의 왕위에 앉지 못할 것이며, 그의 시체는 들에 버려져 낮의 더위와 밤의 추위를 당할 것이라는 선고였습니다. 예레미야는 바룩과 함께 새 두루마리에 이전의 모든 말씀과 더 많은 말씀을 기록했습니다. 하나님의 말씀은 불로도 없앨 수 없으며, 거부한다고 사라지지 않습니다.', E'오늘의 핵심\n하나님의 말씀은 인간의 거부와 파괴 시도에도 불구하고 더욱 강력하게 선포되며, 말씀을 멸시하는 자에게는 심판이 임합니다.\n\n묵상 질문\n1. 하나님의 말씀이 내 삶에서 불편한 진실로 다가올 때, 나는 어떻게 반응하고 있나요?\n2. 여호야김처럼 하나님의 경고를 무시하고 있는 내 삶의 영역은 없나요?\n3. 오늘도 말씀으로 우리를 돌이키려 하시는 하나님의 사랑을 어떻게 받아들일 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-07', E'예루살렘 멸망 (예레미야 39장)', E'예레미야 39장', E'하나님의 긴 인내가 끝나고 마침내 심판의 날이 임했습니다. 시드기야 왕 9년 10월부터 시작된 바벨론의 포위 공격은 11년 4월, 즉 1년 6개월 만에 예루살렘 함락으로 끝을 맺습니다. 예레미야가 그토록 외쳤던 심판의 예언이 현실로 나타난 것입니다. \n\n시드기야 왕은 밤의 어둠을 틈타 도망치려 했지만 여리고 평원에서 붙잡히고 맙니다. 바벨론 왕은 시드기야의 눈앞에서 그의 아들들과 유다의 모든 귀족들을 죽이고, 마지막으로 시드기야의 두 눈을 뽑아버립니다. 자녀들이 죽는 참혹한 광경이 시드기야가 본 마지막 장면이 되었습니다. 하나님의 말씀을 거역한 대가가 얼마나 처참한지를 보여주는 장면입니다.\n\n그러나 심판 가운데서도 하나님의 자비는 계속됩니다. 바벨론 왕은 예레미야를 특별히 보호하라고 명령했고, 사령관 느부사라단은 예레미야를 감옥에서 풀어주어 그다랴에게 맡깁니다. 더 놀라운 것은 예레미야를 구덩이에서 구해준 구스인 에벳멜렉에 대한 구원의 약속입니다. "네가 나를 믿었음이라"(렘 39:18)는 하나님의 선언은 심판의 날에도 믿음으로 행한 자에게는 구원이 있음을 보여줍니다.\n\n아무 소유가 없던 빈민들에게는 오히려 포도원과 밭이 주어졌습니다. 하나님께서는 교만한 자를 낮추시고 겸손한 자를 높이시는 분이십니다. 예루살렘의 멸망은 끝이 아니라 새로운 시작을 위한 하나님의 섭리였습니다. 폐허 속에서도 하나님은 당신의 백성을 위한 회복의 씨앗을 심고 계셨습니다.', E'오늘의 핵심\n예루살렘이 마침내 함락되고 시드기야 왕은 비참한 최후를 맞이했지만, 하나님은 심판 중에도 믿음의 사람들을 보호하시고 새로운 소망의 씨앗을 심으셨습니다.\n\n묵상 질문\n1. 하나님의 경고를 끝까지 무시한 결과가 어떠했는지 돌아보며, 오늘 내게 주시는 하나님의 음성은 무엇인가요?\n2. 심판의 날에도 에벳멜렉처럼 믿음으로 구원받은 사람이 있었는데, 나는 어려운 상황에서도 믿음을 지키고 있나요?\n3. 폐허가 된 예루살렘에서도 하나님이 새 일을 시작하신 것처럼, 내 삶의 무너진 곳에서 하나님이 일하실 영역은 어디일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-08', E'예루살렘 멸망 (예레미야 40장)', E'예레미야 40장', E'예루살렘이 함락되고 시드기야 왕이 비참한 최후를 맞이한 후, 예레미야는 다른 포로들과 함께 사슬에 묶여 바벨론으로 끌려가고 있었습니다. 그러나 라마에서 극적인 전환점을 맞게 됩니다. 바벨론의 사령관 느부사라단이 예레미야를 알아보고 특별히 그를 풀어주면서 놀라운 고백을 합니다. "네 하나님 여호와께서 이 곳에 이 재난을 선포하시더니 여호와께서 그가 말씀하신 대로 행하셨으니"(렘 40:2-3). 이방인 사령관조차도 예루살렘의 멸망이 하나님의 심판임을 인정하고 있는 것입니다.\n\n느부사라단은 예레미야에게 선택권을 줍니다. 바벨론으로 함께 가면 특별 대우를 해주겠다는 제안과 함께, 원한다면 어디든 갈 수 있다고 말합니다. 이때 예레미야는 중대한 결정을 내립니다. 안락한 바벨론행 대신 황폐해진 유다 땅에 남기로 선택한 것입니다. 그는 바벨론 왕이 유다 총독으로 세운 그다랴에게로 향합니다.\n\n그다랴는 미스바를 중심으로 남은 백성들을 모으고 새로운 공동체를 세워나갑니다. 그는 백성들에게 바벨론을 섬기며 평화롭게 살 것을 권면합니다. 이는 단순한 정치적 타협이 아니라, 바벨론을 통해 일하시는 하나님의 섭리를 받아들이는 신앙적 결단이었습니다. 이 소식을 듣고 모압, 암몬, 에돔 등지로 흩어졌던 유다 사람들이 돌아와 포도주와 여름 과일을 거두며 일상을 회복해 나갑니다.\n\n그러나 이 평화로운 재건의 시기에도 어두운 그림자가 드리워집니다. 암몬 왕 바알리스가 이스마엘을 사주해 그다랴를 암살하려 한다는 정보가 들어옵니다. 요하난이 이를 경고하지만 그다랴는 믿으려 하지 않습니다. 하나님의 심판 후에도 여전히 인간의 욕망과 정치적 음모는 계속되고 있었던 것입니다. 예레미야가 남은 백성들과 함께 머물기로 한 것은 바로 이런 혼란 속에서도 하나님의 말씀을 전하고 백성들을 인도하기 위함이었습니다.', E'오늘의 핵심\n예루살렘 멸망 후에도 하나님은 예레미야를 통해 남은 백성들을 돌보시며, 폐허 속에서도 새로운 시작의 가능성을 열어주십니다.\n\n묵상 질문\n1. 예레미야는 왜 안락한 바벨론 대신 황폐한 유다 땅을 선택했을까요?\n2. 실패와 좌절 속에서도 남은 자를 위해 헌신하는 마음이 내게 있나요?\n3. 하나님의 심판 이후에도 계속되는 은혜의 손길을 경험한 적이 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-09', E'예루살렘 멸망 (예레미야 41장)', E'예레미야 41장', E'예루살렘이 함락된 후, 바벨론 왕이 세운 총독 그다랴 치하에서 유다 땅에 남은 백성들은 잠시나마 안정을 찾는 듯했습니다. 그러나 왕족 출신인 이스마엘이 열 사람과 함께 미스바로 와서 그다랴와 함께 떡을 먹던 중에 갑작스럽게 칼을 빼들어 그다랴를 살해합니다. 바벨론의 통치 질서에 순응하며 남은 백성들을 돌보던 그다랴의 죽음은 또 다른 혼란의 시작을 알리는 비극적 사건이었습니다.\n\n이스마엘의 만행은 여기서 그치지 않았습니다. 미스바에 있던 유다 사람들과 갈대아 군사들까지 무참히 살해한 후, 성전에 예물을 드리러 오던 순례자 팔십 명 중 칠십 명까지 속여서 죽이고 시체를 구덩이에 던져버립니다. 열 사람만이 숨겨둔 양식을 대가로 목숨을 건질 수 있었습니다. 이스마엘이 시체를 던진 구덩이는 아사 왕이 북이스라엘의 침략에 대비해 팠던 방어 시설이었는데, 이제는 동족을 살해한 시체로 가득 차게 되었습니다.\n\n이스마엘은 미스바에 남아 있던 왕의 딸들과 백성들을 사로잡아 암몬으로 도망치려 했으나, 요하난과 군 지휘관들이 추격하여 기브온 큰 물가에서 대치하게 됩니다. 사로잡혔던 백성들이 요하난을 보고 기뻐하며 그에게로 돌아오자, 이스마엘은 겨우 여덟 명과 함께 암몬으로 도주합니다. 요하난은 구출한 백성들을 이끌고 베들레헴 근처 게롯김함에 머물며 애굽으로 피신할 준비를 합니다. 바벨론이 임명한 총독이 살해되었으니 보복이 두려웠던 것입니다.\n\n하나님의 심판이 이루어진 후에도 여전히 인간의 탐욕과 정치적 야망은 더 큰 혼란을 낳았습니다. 예레미야를 통해 전해진 하나님의 뜻에 순종했던 그다랴의 죽음과, 그로 인한 백성들의 또 다른 유랑은 불순종이 가져온 비극의 연속을 보여줍니다.', E'오늘의 핵심\n바벨론의 통치 아래 안정을 찾아가던 유다 백성들은 이스마엘의 반란으로 다시 한 번 큰 혼란에 빠지며, 이는 하나님의 섭리를 거스르는 인간의 교만이 초래한 비극임을 보여줍니다.\n\n묵상 질문\n1. 하나님의 심판 이후에도 계속되는 혼란을 통해 우리는 무엇을 깨달아야 할까요?\n2. 그다랴처럼 어려운 시대에 화평을 추구하는 지도자의 역할은 무엇일까요?\n3. 두려움 때문에 애굽으로 도망가려는 백성들에게 하나님은 어떤 마음이셨을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2028-02-10', E'남겨진 남유다 백성의 행동 (예레미야 42장)', E'예레미야 42장', E'예루살렘이 함락되고 총독 그다랴마저 암살당한 후, 남은 백성들은 깊은 두려움에 사로잡혔습니다. 바벨론의 보복이 두려웠던 그들은 군 지휘관들과 함께 예레미야를 찾아와 간절히 청합니다. "당신의 하나님 여호와께서 우리가 마땅히 갈 길과 할 일을 보이시기를 원하나이다"(렘 42:3). 그들은 하나님의 뜻이 무엇이든 순종하겠다고 맹세하며, 여호와를 증인으로 삼기까지 합니다.\n\n열흘 후 하나님의 말씀이 예레미야에게 임합니다. 하나님께서는 놀라운 약속을 주십니다. 만일 그들이 유다 땅에 머물면 하나님께서 그들을 세우고 심으실 것이며, 바벨론 왕의 손에서 구원하시겠다는 것입니다. 더욱 놀라운 것은 하나님께서 "내가 너희에게 내린 재난에 대하여 뜻을 돌이킴이라"고 말씀하신 점입니다. 심판하신 하나님께서 이제는 회복의 손길을 내미시는 것입니다.\n\n그러나 동시에 엄중한 경고도 주어집니다. 만일 그들이 애굽으로 도피한다면, 그곳에서도 칼과 기근과 전염병을 피할 수 없을 것이라는 말씀입니다. 전쟁이 없고 양식이 풍부해 보이는 애굽은 사실 또 다른 심판의 장소가 될 것입니다. 예레미야는 이미 그들이 마음속으로 애굽행을 결정했음을 간파하고 있었습니다. "너희가 너희 마음을 속였느니라"는 선지자의 지적은 그들의 위선적인 신앙 태도를 정확히 꿰뚫고 있습니다.\n\n하나님의 말씀을 구하면서도 이미 자기 마음의 결정을 내려놓지 못하는 이 모습은 오늘 우리의 신앙생활에도 깊은 도전을 줍니다. 진정한 순종은 하나님의 뜻을 묻기 전에 내 계획을 내려놓는 것에서 시작됩니다.', E'오늘의 핵심\n하나님께서는 심판 이후에도 회복의 은혜를 베푸시지만, 그 은혜는 온전한 믿음과 순종을 통해서만 누릴 수 있습니다.\n\n묵상 질문\n1. 나는 하나님의 뜻을 구하면서도 이미 내 마음속 결정을 고집하고 있지는 않나요?\n2. 두려움 때문에 하나님의 약속보다 세상의 안전을 택하려는 유혹은 없나요?\n3. "내가 너희에게 내린 재난에 대하여 뜻을 돌이킴이라"는 말씀이 내게 주는 위로는 무엇인가요?');
